      rel="stylesheet"
    />
  </head>
  <body
    class="bg-[#0c101d] text-[#e2e8f0] font-sans antialiased overflow-x-hidden selection:bg-blue-500/30 selection:text-white min-h-screen"
  >
    <!-- Mobile sidebar overlay backdrop -->
    <div id="sidebar-overlay" class="fixed inset-0 bg-black/60 z-30 hidden lg:hidden transition-opacity duration-300" aria-hidden="true"></div>
    <slot />
    <!-- Mobile sidebar toggle script -->
    <script>
      function initMobileSidebar() {
        const overlay = document.getElementById('sidebar-overlay');
        const sidebar = document.querySelector('.mobile-sidebar');
        const toggleBtn = document.getElementById('mobile-menu-toggle');

        if (!overlay || !sidebar || !toggleBtn) return;

        function openSidebar() {
          sidebar.classList.remove('hidden');
          overlay.classList.remove('hidden');
          document.body.style.overflow = 'hidden';
        }

        function closeSidebar() {
          sidebar.classList.add('hidden');
          overlay.classList.add('hidden');
          document.body.style.overflow = '';
        }

        toggleBtn.addEventListener('click', (e) => {
          e.stopPropagation();
          if (sidebar.classList.contains('hidden')) {
            openSidebar();
          } else {
            closeSidebar();
          }
        });

        // Also wire up close buttons inside the sidebar
        const closeBtns = sidebar.querySelectorAll('#mobile-menu-close, #mobile-menu-close-bottom');
        closeBtns.forEach(btn => {
          btn.addEventListener('click', (e) => {
            e.stopPropagation();
            closeSidebar();
          });
        });

        overlay.addEventListener('click', closeSidebar);

        // Close on Escape key
        document.addEventListener('keydown', (e) => {
          if (e.key === 'Escape' && !sidebar.classList.contains('hidden')) {
            closeSidebar();
          }
        });
      }

      // Run on DOM ready
      if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initMobileSidebar);
      } else {
        initMobileSidebar();
      }
    </script>
  </body>
</html>

