---
import Layout from "../layouts/Layout.astro";
import {
  Rocket,
  Package,
  TrendingUp,
  Settings,
  Search,
  HelpCircle,
  Sparkles,
  X,
  CircleDot,
  SlidersHorizontal,
  ArrowUpDown,
} from "@lucide/astro";
import fs from "node:fs";
import path from "node:path";
import { parse } from "csv-parse/sync";

// ── Load drones ──
const dronesCsv = fs.readFileSync(path.join(process.cwd(), "src/data/drones.csv"), "utf-8");
const dronesRaw = parse(dronesCsv, { columns: true, skip_empty_lines: true, cast: true });
const drones = dronesRaw.map((r: any) => ({
  _type: "drone",
  id: String(r.id),
  location: String(r.location),
  status: String(r.status),
  attempts: Number(r.attempts),
  success: Number(r.success),
  pct: Number(r.pct),
  _searchText: [String(r.id), String(r.location), String(r.status), String(r.attempts), String(r.success), String(r.pct)].join(" ").toLowerCase(),
}));

// ── Load deliveries ──
const deliveriesCsv = fs.readFileSync(path.join(process.cwd(), "src/data/deliveries.csv"), "utf-8");
const deliveriesRaw = parse(deliveriesCsv, { columns: true, skip_empty_lines: true, cast: true });
const deliveries = deliveriesRaw.map((r: any) => ({
  _type: "delivery",
  id: String(r.id),
  address: String(r.address),
  addressDetail: String(r.addressDetail),
  drone: String(r.drone),
  status: String(r.status),
  eta: String(r.eta),
  etaDetail: String(r.etaDetail),
  deliveryType: String(r.type),
  _searchText: [String(r.id), String(r.address), String(r.addressDetail), String(r.drone), String(r.status), String(r.eta), String(r.etaDetail), String(r.type)].join(" ").toLowerCase(),
}));

const allRecords = [...drones, ...deliveries];
const allStatuses = [...new Set(allRecords.map((r: any) => r.status))];
const totalRecords = allRecords.length;

// Serialize for client-side embedding
const allRecordsJson = JSON.stringify(allRecords);
