        </table>
        <div id="empty-state" class="hidden flex-col items-center justify-center py-16 text-center">
          <Search class="w-10 h-10 text-slate-600 mb-3" />
          <p class="text-sm font-semibold text-slate-400">No results found</p>
          <p class="text-xs text-slate-500 mt-1">Try adjusting your search query or filters</p>
        </div>
        <div id="initial-state" class="flex flex-col items-center justify-center py-16 text-center">
          <Sparkles class="w-10 h-10 text-slate-600 mb-3" />
          <p class="text-sm font-semibold text-slate-400">Search across {totalRecords} records</p>
          <p class="text-xs text-slate-500 mt-1">Type in the search bar above to find drones and deliveries</p>
        </div>
      </div>

      <!-- Pagination -->
      <div id="pagination-bar" class="hidden items-center justify-between text-xs text-slate-400 font-semibold bg-[#0e1220] border border-[#192239] rounded-lg p-4">
        <span id="pagination-indicator">Page <strong class="text-white" id="page-current">1</strong> of <strong class="text-white" id="page-total">1</strong></span>
        <div class="flex gap-2">
          <button id="prev-page-btn" class="px-3 py-1.5 bg-[#161d31] hover:bg-[#1a233b] hover:text-white rounded border border-[#212c49] text-slate-400 cursor-pointer transition-colors disabled:opacity-30 disabled:cursor-not-allowed">Prev</button>
          <button id="next-page-btn" class="px-3 py-1.5 bg-[#161d31] hover:bg-[#1a233b] hover:text-white rounded border border-[#212c49] text-slate-400 cursor-pointer transition-colors disabled:opacity-30 disabled:cursor-not-allowed">Next</button>
