<!-- Embedded search data -->
<script>
  window.__ALL_RECORDS__ = JSON.parse('{allRecordsJson.replace(/'/g, "\\'")}');
</script>

<!-- Search Application -->
<script>
  (function () {
    const ALL_RECORDS = window.__ALL_RECORDS__;

    // ── DOM refs ──
    const searchInput = document.getElementById("search-input");
    const clearBtn = document.getElementById("clear-search-btn");
    const sortSelect = document.getElementById("sort-select");
    const resultsBody = document.getElementById("results-body");
    const resultsTable = document.getElementById("results-table");
    const emptyState = document.getElementById("empty-state");
    const initialState = document.getElementById("initial-state");
    const statsBar = document.getElementById("stats-bar");
    const resultsCount = document.getElementById("results-count");
    const resultsSummary = document.getElementById("results-summary");
    const paginationBar = document.getElementById("pagination-bar");
    const pageCurrent = document.getElementById("page-current");
    const pageTotal = document.getElementById("page-total");
    const prevPageBtn = document.getElementById("prev-page-btn");
    const nextPageBtn = document.getElementById("next-page-btn");

    // ── State ──
    let query = "";
    let typeFilter = "all";
    let statusFilter = "all";
    let sortMode = "relevance";
    let currentPage = 1;
    const ITEMS_PER_PAGE = 10;

    // ── Read URL params on load ──
    function readUrlParams() {
      const params = new URLSearchParams(window.location.search);
      const q = params.get("q") || "";
      const t = params.get("type") || "all";
      const s = params.get("status") || "all";
      const sort = params.get("sort") || "relevance";
      if (q) searchInput.value = q;
      query = q;
      typeFilter = t;
      statusFilter = s;
      sortMode = sort;
      sortSelect.value = sort;

      // Sync filter chips
      document.querySelectorAll(".type-chip").forEach((btn) => {
        const val = btn.getAttribute("data-value");
        toggleChip(btn, val === t);
      });
      document.querySelectorAll(".status-chip").forEach((btn) => {
        const val = btn.getAttribute("data-value");
        toggleChip(btn, val === s);
      });

      if (q || t !== "all" || s !== "all") {
        applyAll();
      }
    }

    // ── Update URL ──
    function updateUrl() {
      const params = new URLSearchParams();
      if (query) params.set("q", query);
      if (typeFilter !== "all") params.set("type", typeFilter);
      if (statusFilter !== "all") params.set("status", statusFilter);
      if (sortMode !== "relevance") params.set("sort", sortMode);
      const newUrl = window.location.pathname + (params.toString() ? "?" + params.toString() : "");
      window.history.replaceState(null, "", newUrl);
    }

    // ── Filter ──
    function filterRecords() {
      const q = query.toLowerCase().trim();
      let results = ALL_RECORDS.slice();

      // Type filter
      if (typeFilter !== "all") {
        results = results.filter((r) => r._type === typeFilter);
      }

      // Status filter
      if (statusFilter !== "all") {
        results = results.filter((r) => r.status === statusFilter);
      }

      // Text search
      if (q) {
        const terms = q.split(/\s+/);
        results = results.filter((r) => {
          return terms.every((term) => r._searchText.includes(term));
        });
      }

      return results;
    }

    // ── Sort ──
    function sortRecords(records) {
      const mode = sortMode;
      if (mode === "relevance") return records; // preserve filter order

      const sorted = records.slice();
      sorted.sort((a, b) => {
        let cmp = 0;
        switch (mode) {
          case "id-asc": cmp = a.id.localeCompare(b.id); break;
          case "id-desc": cmp = b.id.localeCompare(a.id); break;
          case "status-asc": cmp = a.status.localeCompare(b.status); break;
          case "status-desc": cmp = b.status.localeCompare(a.status); break;
          case "pct-desc": cmp = (b.pct || 0) - (a.pct || 0); break;
          case "pct-asc": cmp = (a.pct || 0) - (b.pct || 0); break;
          case "attempts-desc": cmp = (b.attempts || 0) - (a.attempts || 0); break;
          case "attempts-asc": cmp = (a.attempts || 0) - (b.attempts || 0); break;
          default: cmp = 0;
        }
        return cmp;
      });
      return sorted;
    }

    // ── Render ──
    function render(results) {
      const total = results.length;
      const totalPages = Math.ceil(total / ITEMS_PER_PAGE) || 1;

      // Clamp page
      if (currentPage > totalPages) currentPage = totalPages;
      if (currentPage < 1) currentPage = 1;

      const startIdx = (currentPage - 1) * ITEMS_PER_PAGE;
      const pageItems = results.slice(startIdx, startIdx + ITEMS_PER_PAGE);

      // Show/hide states
      const hasQuery = query.trim().length > 0;
      const hasFilters = typeFilter !== "all" || statusFilter !== "all";
      const isSearching = hasQuery || hasFilters;

      if (!isSearching && total === ALL_RECORDS.length) {
        // Initial state
        resultsTable.classList.add("hidden");
        emptyState.classList.add("hidden");
        initialState.classList.remove("hidden");
        paginationBar.classList.add("hidden");
        statsBar.querySelector("span").textContent = ALL_RECORDS.length + " total records";
        resultsSummary.textContent = "Type a query to begin searching";
      } else if (total === 0) {
        // Empty
        resultsTable.classList.add("hidden");
        initialState.classList.add("hidden");
        emptyState.classList.remove("hidden");
        paginationBar.classList.add("hidden");
        resultsCount.textContent = "0";
        resultsSummary.textContent = "No matches — try different keywords or filters";
      } else {
        // Results
        resultsTable.classList.remove("hidden");
        initialState.classList.add("hidden");
        emptyState.classList.add("hidden");
        paginationBar.classList.remove("hidden");

        resultsCount.textContent = String(total);
        resultsSummary.textContent = "matching records";
        pageCurrent.textContent = String(currentPage);
        pageTotal.textContent = String(totalPages);
        prevPageBtn.disabled = currentPage <= 1;
        nextPageBtn.disabled = currentPage >= totalPages;

        // Build rows
        let html = "";
        pageItems.forEach((r) => {
          if (r._type === "drone") {
            const pctClass = r.pct >= 95 ? "text-[#10b981]" : r.pct >= 90 ? "text-blue-400" : "text-amber-400";
            const statusClass =
              r.status === "IN-TRANSIT" ? "bg-blue-500/10 border-blue-500/20 text-blue-400" :
              r.status === "MAINTENANCE" ? "bg-rose-500/10 border-rose-500/20 text-rose-400" :
              "bg-slate-500/10 border-slate-500/25 text-slate-400";
            html += `<tr class="border-b border-[#192239]/60 hover:bg-[#111625]/50 transition-colors">
              <td class="py-3 px-5"><span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[9px] font-bold uppercase bg-indigo-500/10 text-indigo-400 border border-indigo-500/20">Drone</span></td>
              <td class="py-3 px-5 font-mono text-xs font-bold text-slate-200">${esc(r.id)}</td>
              <td class="py-3 px-5 text-slate-300 font-medium">${esc(r.location)}</td>
              <td class="py-3 px-5 text-slate-500 text-[10px]">—</td>
              <td class="py-3 px-5 text-slate-500 text-[10px]">—</td>
              <td class="py-3 px-5"><div class="inline-flex items-center gap-1.5 py-0.5 px-2 rounded-md text-[10px] font-bold uppercase tracking-wider border ${statusClass}"><span class="relative flex h-1.5 w-1.5"><span class="animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${r.status === 'IN-TRANSIT' ? 'bg-blue-400' : r.status === 'MAINTENANCE' ? 'bg-rose-400' : 'bg-slate-400'}"></span><span class="relative inline-flex rounded-full h-1.5 w-1.5 ${r.status === 'IN-TRANSIT' ? 'bg-blue-500' : r.status === 'MAINTENANCE' ? 'bg-rose-500' : 'bg-slate-500'}"></span></span>${esc(r.status)}</div></td>
              <td class="py-3 px-5 text-right"><span class="font-mono text-xs font-bold ${pctClass}">${r.pct}%</span> <span class="text-[10px] text-slate-500">(${r.success}/${r.attempts})</span></td>
            </tr>`;
          } else {
            const statusClass =
              r.status === "IN TRANSIT" ? "bg-blue-500/10 border-blue-500/20 text-blue-400" :
              r.status === "DELAYED" ? "bg-amber-500/10 border-amber-500/20 text-amber-400" :
              r.status === "FINAL APPROACH" ? "bg-emerald-500/10 border-emerald-500/20 text-emerald-400" :
              "bg-slate-500/10 border-slate-500/25 text-slate-400";
            html += `<tr class="border-b border-[#192239]/60 hover:bg-[#111625]/50 transition-colors">
              <td class="py-3 px-5"><span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[9px] font-bold uppercase bg-amber-500/10 text-amber-400 border border-amber-500/20">Delivery</span></td>
              <td class="py-3 px-5 font-mono text-xs font-bold text-slate-200">${esc(r.id)}</td>
              <td class="py-3 px-5 text-slate-300 font-medium">${esc(r.address)}</td>
              <td class="py-3 px-5 text-slate-400 text-[10px]">${esc(r.addressDetail)}</td>
              <td class="py-3 px-5 font-mono text-[11px] text-slate-300">${esc(r.drone)}</td>
              <td class="py-3 px-5"><div class="inline-flex items-center gap-1.5 py-0.5 px-2 rounded-md text-[10px] font-bold uppercase tracking-wider border ${statusClass}">${esc(r.status)}</div></td>
              <td class="py-3 px-5 text-right font-mono text-xs font-bold text-slate-300">ETA ${esc(r.eta)} <span class="text-[10px] text-slate-500 font-normal">${esc(r.etaDetail)}</span></td>
            </tr>`;
          }
        });
        resultsBody.innerHTML = html;
      }

      // Clear button visibility
      if (query) {
        clearBtn.classList.remove("hidden");
      } else {
        clearBtn.classList.add("hidden");
      }
    }

    function esc(s) {
      if (!s) return "";
      return String(s).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");
    }

    // ── Apply all ──
    function applyAll() {
      const filtered = filterRecords();
      const sorted = sortRecords(filtered);
      updateUrl();
      render(sorted);
    }

    // ── Chip helpers ──
    function toggleChip(btn, active) {
      if (active) {
        btn.classList.add("active", "bg-blue-500/15", "border-blue-500/30", "text-blue-400");
        btn.classList.remove("bg-transparent", "border-[#1b253b]", "text-slate-400");
      } else {
        btn.classList.remove("active", "bg-blue-500/15", "border-blue-500/30", "text-blue-400");
        btn.classList.add("bg-transparent", "border-[#1b253b]", "text-slate-400");
      }
    }

    // ── Event: search input ──
    let debounceTimer;
    searchInput.addEventListener("input", () => {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(() => {
        query = searchInput.value;
        currentPage = 1;
        applyAll();
      }, 200);
    });

    // ── Event: Enter key on search (from other pages, handled via URL) ──
    searchInput.addEventListener("keydown", (e) => {
      if (e.key === "Escape") {
        searchInput.value = "";
        query = "";
        currentPage = 1;
        applyAll();
      }
    });

    // ── Event: clear button ──
    clearBtn.addEventListener("click", () => {
      searchInput.value = "";
      query = "";
      currentPage = 1;
      applyAll();
      searchInput.focus();
    });

    // ── Event: type filter chips ──
    document.querySelectorAll(".type-chip").forEach((btn) => {
      btn.addEventListener("click", () => {
        document.querySelectorAll(".type-chip").forEach((b) => toggleChip(b, false));
        toggleChip(btn, true);
        typeFilter = btn.getAttribute("data-value") || "all";
        currentPage = 1;
        applyAll();
      });
    });

    // ── Event: status filter chips ──
    document.querySelectorAll(".status-chip").forEach((btn) => {
      btn.addEventListener("click", () => {
        document.querySelectorAll(".status-chip").forEach((b) => toggleChip(b, false));
        toggleChip(btn, true);
        statusFilter = btn.getAttribute("data-value") || "all";
        currentPage = 1;
        applyAll();
      });
    });

    // ── Event: sort select ──
    sortSelect.addEventListener("change", () => {
      sortMode = sortSelect.value;
      currentPage = 1;
      applyAll();
    });

    // ── Event: pagination ──
    prevPageBtn.addEventListener("click", () => {
      if (currentPage > 1) {
        currentPage--;
        applyAll();
      }
    });
    nextPageBtn.addEventListener("click", () => {
      const filtered = filterRecords();
      const totalPages = Math.ceil(filtered.length / ITEMS_PER_PAGE) || 1;
      if (currentPage < totalPages) {
        currentPage++;
        applyAll();
      }
    });

    // ── Keyboard shortcut: "/" focuses search ──
    document.addEventListener("keydown", (e) => {
      if (e.key === "/" && document.activeElement !== searchInput && document.activeElement?.tagName !== "INPUT" && document.activeElement?.tagName !== "TEXTAREA" && document.activeElement?.tagName !== "SELECT") {
        e.preventDefault();
        searchInput.focus();
        searchInput.select();
      }
    });

    // ── Init ──
    readUrlParams();
  })();
</script>

<style>
