      if (q) {
        window.location.href = '/pluto/search?q=' + q + '&type=delivery';
      }
    }

    const headerSearch = document.getElementById('delivery-header-search');
    if (headerSearch) {
      headerSearch.addEventListener('keydown', function(e) {
