const fs = require('fs');
const c = fs.readFileSync('dist/search/index.html', 'utf8');

// Extract the embedded records
const m = c.match(/const records = "(.+?)";/);
if (!m) { console.log('FATAL: No embedded data found!'); process.exit(1); }

const jsonStr = m[1].replace(/\\"/g, '"').replace(/\\\\/g, '\\');
let data;
try {
  data = JSON.parse(jsonStr);
} catch(e) {
  console.log('FATAL: JSON parse error:', e.message.substring(0, 100));
  process.exit(1);
}

console.log('Data loaded:', data.length, 'records');

// Test the EXACT same filter logic as the client-side code
function simulateSearch(query, typeFilter, statusFilter) {
  let results = data.slice();
  if (typeFilter !== "all") {
    results = results.filter(r => r._type === typeFilter);
  }
  if (statusFilter !== "all") {
    results = results.filter(r => r.status === statusFilter);
  }
  if (query) {
    const terms = query.toLowerCase().trim().split(/\s+/);
    results = results.filter(r => terms.every(term => r._searchText.includes(term)));
  }
  return results;
}

// Test 1: Search for "982" (should be 0)
const r1 = simulateSearch("982", "all", "all");
console.log('\n1. Query "982" (all types):', r1.length, 'results');

// Test 2: Search for "902" (should match DRN-X902)
const r2 = simulateSearch("902", "all", "all");
console.log('2. Query "902" (all types):', r2.length, 'results');
if (r2.length > 0) console.log('   Found:', r2[0].id, r2[0]._type);

// Test 3: Search for "DRN" (should match ALL drones)
const r3 = simulateSearch("DRN", "all", "all");
console.log('3. Query "DRN" (all types):', r3.length, 'results');

// Test 4: Search for "north" (should match many)
const r4 = simulateSearch("north", "all", "all");
console.log('4. Query "north" (all types):', r4.length, 'results');

// Test 5: Search for "delayed" (should match 2 deliveries)
const r5 = simulateSearch("delayed", "all", "all");
console.log('5. Query "delayed" (all types):', r5.length, 'results');

// Test 6: The initial state check — what happens with empty query
const r6 = simulateSearch("", "all", "all");
console.log('6. Empty query (no filters):', r6.length, 'results (should be', data.length, ')');

// Test 7: Search with type=drone filter
const r7 = simulateSearch("x90", "drone", "all");
console.log('7. Query "x90" + type=drone:', r7.length, 'results');

// Check if _searchText is populated on all records
const missingSearchText = data.filter(r => !r._searchText);
console.log('\nRecords missing _searchText:', missingSearchText.length);
if (missingSearchText.length > 0) {
  console.log('  Example:', JSON.stringify(missingSearchText[0]).substring(0, 200));
}

// Show a sample _searchText
console.log('Sample _searchText (first drone):', data[0]._searchText.substring(0, 80));
console.log('Sample _searchText (first delivery):', data.find(r=>r._type==='delivery')._searchText.substring(0, 80));

