// Simulate the EXACT new filter logic
function simulateSearch(query, typeFilter, statusFilter) {
  const q = query.toLowerCase().trim();
  let results = data.slice();

  if (typeFilter !== "all") {
    results = results.filter(r => r._type === typeFilter);
  }
  if (statusFilter !== "all") {
    results = results.filter(r => r.status === statusFilter);
  }

  let fuzzy = false;
  if (q) {
    const terms = q.split(/\s+/);
    results = results.filter(r => terms.every(term => r._searchText.includes(term)));

    if (results.length === 0 && !q.includes(" ") && q.length >= 2) {
      const chars = q.split("");
      let fuzzyResults = data.slice();
      if (typeFilter !== "all") fuzzyResults = fuzzyResults.filter(r => r._type === typeFilter);
      if (statusFilter !== "all") fuzzyResults = fuzzyResults.filter(r => r.status === statusFilter);
      fuzzyResults = fuzzyResults.filter(r => chars.every(ch => r._searchText.includes(ch)));
      if (fuzzyResults.length > 0) {
        results = fuzzyResults;
        fuzzy = true;
      }
    }
  }

  return { results, fuzzy };
}

