// ── Filter ──
let fuzzyActive = false;

function filterRecords() {
  const q = query.toLowerCase().trim();
  let results = ALL_RECORDS.slice();

  // Type filter
  if (typeFilter !== "all") {
    results = results.filter((r) => r._type === typeFilter);
  }

  // Status filter
  if (statusFilter !== "all") {
    results = results.filter((r) => r.status === statusFilter);
  }

  // Text search
  fuzzyActive = false;
  if (q) {
    const terms = q.split(/\s+/);

    // 1) Exact substring matching (primary)
    results = results.filter((r) => {
      return terms.every((term) => r._searchText.includes(term));
    });

    // 2) Fuzzy fallback: if no results and query has no spaces, match records
    //    that contain every individual character of the query (any order).
    //    This catches typos like "982" → matches "8829" (delivery) etc.
    if (results.length === 0 && !q.includes(" ") && q.length >= 2) {
      const chars = q.split("");
      results = ALL_RECORDS.slice();

      if (typeFilter !== "all") {
        results = results.filter((r) => r._type === typeFilter);
      }
      if (statusFilter !== "all") {
        results = results.filter((r) => r.status === statusFilter);
      }

      results = results.filter((r) => {
        return chars.every((ch) => r._searchText.includes(ch));
      });

      if (results.length > 0) {
        fuzzyActive = true;
      }
    }
  }

  return results;
}

