// ── Detail Drawer ──
const drawer = document.getElementById("detail-drawer");
const drawerOverlay = document.getElementById("drawer-overlay");
const drawerTitle = document.getElementById("drawer-title");
const drawerBody = document.getElementById("drawer-body");
const closeDrawerBtn = document.getElementById("close-drawer-btn");

function openDrawer(record) {
  if (!drawer || !drawerBody || !drawerTitle) return;

  const isDrone = record._type === "drone";
  drawerTitle.textContent = isDrone ? record.id : record.id;

  // Highlight the drawer border
  drawer.classList.remove("hidden");
  drawer.classList.add("flex");

  let html = "";
  if (isDrone) {
    const statusColor =
      record.status === "IN-TRANSIT" ? "blue" :
      record.status === "MAINTENANCE" ? "rose" : "slate";
    const pctColor =
      record.pct >= 95 ? "#10b981" : record.pct >= 90 ? "#60a5fa" : "#f59e0b";

    html += `<div class="flex items-center gap-2 mb-4">
      <span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[9px] font-bold uppercase bg-indigo-500/10 text-indigo-400 border border-indigo-500/20">Drone</span>
      <span class="inline-flex items-center gap-1.5 py-0.5 px-2 rounded-md text-[10px] font-bold uppercase tracking-wider border bg-${statusColor}-500/10 border-${statusColor}-500/20 text-${statusColor}-400">${esc(record.status)}</span>
    </div>`;

    html += `<div class="space-y-3">`;
    html += detailRow("ID", record.id, true);
    html += detailRow("Location", record.location);
    html += detailRow("Status", record.status);
    html += detailRow("Total Attempts", String(record.attempts));
    html += detailRow("Successful", String(record.success));
    html += detailRow("Success Rate", record.pct + "%", false, pctColor);
    html += `</div>`;

    // Progress bar
    html += `<div class="mt-4 pt-4 border-t border-[#192239]">
      <div class="flex justify-between text-[10px] text-slate-400 font-medium mb-1.5">
        <span>Success Rate</span>
        <span style="color:${pctColor}" class="font-bold">${record.pct}%</span>
      </div>
      <div class="w-full h-1.5 bg-[#172033] rounded-full overflow-hidden">
        <div class="h-full rounded-full transition-all" style="width:${record.pct}%; background:${pctColor}"></div>
      </div>
      <p class="text-[10px] text-slate-500 mt-1.5">${record.success} of ${record.attempts} attempts successful</p>
    </div>`;
  } else {
    const statusColor =
      record.status === "IN TRANSIT" ? "blue" :
      record.status === "DELAYED" ? "amber" :
      record.status === "FINAL APPROACH" ? "emerald" : "slate";

    html += `<div class="flex items-center gap-2 mb-4">
      <span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[9px] font-bold uppercase bg-amber-500/10 text-amber-400 border border-amber-500/20">Delivery</span>
      <span class="inline-flex items-center gap-1.5 py-0.5 px-2 rounded-md text-[10px] font-bold uppercase tracking-wider border bg-${statusColor}-500/10 border-${statusColor}-500/20 text-${statusColor}-400">${esc(record.status)}</span>
    </div>`;

    html += `<div class="space-y-3">`;
    html += detailRow("Delivery ID", record.id, true);
    html += detailRow("Address", record.address);
    html += detailRow("Detail", record.addressDetail);
    html += detailRow("Assigned Drone", record.drone, true);
    html += detailRow("Status", record.status);
    html += detailRow("ETA", record.eta);
    html += detailRow("ETA Detail", record.etaDetail);
    html += detailRow("Type", record.deliveryType);
    html += `</div>`;
  }

  drawerBody.innerHTML = html;

  // Mobile overlay
  if (drawerOverlay && window.innerWidth < 1024) {
    drawerOverlay.classList.remove("hidden");
    document.body.style.overflow = "hidden";
  }
}

function detailRow(label, value, mono, color) {
  const valClass = mono ? "font-mono text-slate-200" : "text-slate-200";
  const valStyle = color ? ` style="color:${color}"` : "";
  return `<div class="flex justify-between items-start gap-4 py-2 border-b border-[#192239]/50">
    <span class="text-[10px] font-bold text-slate-500 uppercase tracking-wider shrink-0">${label}</span>
    <span class="text-xs font-medium text-right ${valClass}"${valStyle}>${esc(String(value))}</span>
  </div>`;
}

function closeDrawer() {
  if (!drawer) return;
  drawer.classList.add("hidden");
  drawer.classList.remove("flex");
  if (drawerOverlay) {
    drawerOverlay.classList.add("hidden");
    document.body.style.overflow = "";
  }
}

// Click delegation on table body
resultsBody.addEventListener("click", (e) => {
  const row = e.target.closest("tr[data-record]");
  if (!row) return;

  // Highlight selected row
  resultsBody.querySelectorAll("tr.bg-blue-950\\/30").forEach((r) => {
    r.classList.remove("bg-blue-950/30", "border-l-2", "border-blue-500");
  });
  row.classList.add("bg-blue-950/30", "border-l-2", "border-blue-500");

  // Parse and display
  try {
    const record = JSON.parse(row.getAttribute("data-record"));
    openDrawer(record);
  } catch (err) {
    // ignore parse errors from malformed data
  }
});

// Close button
if (closeDrawerBtn) {
  closeDrawerBtn.addEventListener("click", closeDrawer);
}

// Overlay click
if (drawerOverlay) {
  drawerOverlay.addEventListener("click", closeDrawer);
}

// Escape key closes drawer
document.addEventListener("keydown", (e) => {
  if (e.key === "Escape" && drawer && !drawer.classList.contains("hidden")) {
    closeDrawer();
  }
});

// ── Init ──
readUrlParams();

