// ── Load deliveries.csv ──
const deliveriesCsv = fs.readFileSync(
  path.join(process.cwd(), "src/data/deliveries.csv"),
  "utf-8"
);
const deliveriesRaw = parse(deliveriesCsv, {
  columns: true,
  skip_empty_lines: true,
  cast: true,
});
const allDeliveries = deliveriesRaw.map((r: any) => ({
  id: String(r.id),
  address: String(r.address),
  addressDetail: String(r.addressDetail),
  drone: String(r.drone),
  status: String(r.status),
  eta: String(r.eta),
  etaDetail: String(r.etaDetail),
  type: String(r.type),
  // Normalize for fuzzy matching: strip "DR-" prefix + dashes → lowercase
  normalizedDrone: String(r.drone)
    .replace(/^DR-/, "")
    .replace(/-/g, "")
    .toLowerCase(),
}));

// ── Fuzzy match deliveries → drones (Levenshtein distance) ──
function levenshtein(a: string, b: string): number {
  const m = a.length,
    n = b.length;
  const dp: number[][] = Array.from({ length: m + 1 }, () =>
    Array(n + 1).fill(0)
  );
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      dp[i][j] =
        a[i - 1] === b[j - 1]
          ? dp[i - 1][j - 1]
          : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
    }
  }
  return dp[m][n];
}

// Normalize drone ID: strip "DRN-" → lowercase
function normalizeDroneId(id: string): string {
  return id.replace(/^DRN-/, "").toLowerCase();
}

// Build drone→deliveries map: for each drone, find deliveries with closest match
const droneDeliveriesMap: Record<string, any[]> = {};
drones.forEach((drone: any) => {
  const dNorm = normalizeDroneId(drone.id);
  const matched: any[] = [];

  allDeliveries.forEach((del: any) => {
    // Only consider deliveries whose normalized drone shares the same first letter
    // (heuristic: DR-M1-44 → "m144" should match DRN-M441 → "m441")
    if (del.normalizedDrone[0] === dNorm[0]) {
      const dist = levenshtein(del.normalizedDrone, dNorm);
      // Threshold: allow up to 3 edits for a match
      if (dist <= 3) {
        matched.push({ ...del, _score: dist });
      }
    }
  });

  // Sort by score (best match first)
  matched.sort((a, b) => a._score - b._score);
  droneDeliveriesMap[drone.id] = matched;
});

// Serialize for client-side embedding
const droneDeliveriesJson = JSON.stringify(droneDeliveriesMap);
const allDeliveriesJson = JSON.stringify(allDeliveries);

