const fs = require('fs');
let c = fs.readFileSync('src/pages/index.astro', 'utf8');

// ── 1. Replace the entire right sidebar drawer ──
const drawerStart = c.indexOf('<!-- RIGHT SIDEBAR (Delivery Logs) -->');
const drawerEnd = c.indexOf('</aside>', drawerStart) + '</aside>'.length;

const newDrawer = `<!-- RIGHT SIDEBAR (Drone Detail Drawer) -->
      <aside
        id="drone-detail-drawer"
        class="hidden w-80 lg:w-96 bg-[#0e1220] flex-col shrink-0 border-l border-[#192239] transition-all duration-300 fixed lg:relative right-0 inset-y-0 z-50 shadow-2xl lg:shadow-none"
      >
        <div class="p-5 border-b border-[#192239] flex items-center justify-between shrink-0">
          <div>
            <h3 class="text-sm font-extrabold text-white tracking-wide" id="drawer-drone-id">Drone Detail</h3>
            <p class="text-[10px] text-slate-500 mt-0.5">Click a fleet row to inspect</p>
          </div>
          <button id="drone-drawer-close-btn" class="p-1.5 bg-[#171f34] text-slate-400 hover:text-white rounded transition-colors cursor-pointer" aria-label="Close detail drawer">
            <X class="w-4 h-4" />
          </button>
        </div>
        <div class="flex-1 overflow-y-auto p-5 space-y-5" id="drone-drawer-body">
          <p class="text-xs text-slate-500 text-center py-12">Click a drone row to see full details and linked deliveries</p>
        </div>
      </aside>`;

c = c.substring(0, drawerStart) + newDrawer + c.substring(drawerEnd);
console.log('Replaced drawer');

// ── 2. Add data-id to drone rows ──
// Find: class="...drone-row..." and add data-id
c = c.replace(
  /class="([^"]*drone-row[^"]*)"/g,
  'class="$1 cursor-pointer" data-id={\`\${drone.id}\`}'
);
console.log('Added data-id to drone rows');

// ── 3. Replace the old script with new logic ──
const scriptStart = c.indexOf('<!-- Interactive drawer script -->');
const scriptEnd = c.lastIndexOf('</script>') + '</script>'.length;

const newScript = `<!-- Drone detail drawer + data embedding scripts -->
<script>
  window.__DRONE_DELIVERIES__ = {JSON.stringify(droneDeliveriesMap)};
</script>
<script>
  window.__ALL_DELIVERIES__ = {JSON.stringify(allDeliveries)};
</script>
<script>
  (function () {
    const DRONE_DELIVERIES = window.__DRONE_DELIVERIES__;
    const ALL_DELIVERIES = window.__ALL_DELIVERIES__;

    const drawer = document.getElementById('drone-detail-drawer');
    const drawerBody = document.getElementById('drone-drawer-body');
    const drawerDroneId = document.getElementById('drawer-drone-id');
    const closeBtn = document.getElementById('drone-drawer-close-btn');

    // ── Pagination (preserved from original) ──
    let currentPage = 1;
    const itemsPerPage = 7;
    const rows = document.querySelectorAll('.drone-row');
    const totalItems = rows.length;
    const totalPages = Math.ceil(totalItems / itemsPerPage);
    const prevBtn = document.getElementById('prev-page-btn');
    const nextBtn = document.getElementById('next-page-btn');
    const rangeStart = document.getElementById('range-start');
    const rangeEnd = document.getElementById('range-end');

    function updatePagination() {
      if (!prevBtn || !nextBtn || !rangeStart || !rangeEnd) return;
