// ── Pagination (preserved) ──
let currentPage = 1;
const itemsPerPage = 7;
const rows = document.querySelectorAll(".drone-row");
const totalItems = rows.length;
const totalPages = Math.ceil(totalItems / itemsPerPage);
const prevBtn = document.getElementById("prev-page-btn");
const nextBtn = document.getElementById("next-page-btn");
const rangeStart = document.getElementById("range-start");
const rangeEnd = document.getElementById("range-end");

function updatePagination() {
  if (!prevBtn || !nextBtn || !rangeStart || !rangeEnd) return;
  prevBtn.disabled = currentPage === 1;
  nextBtn.disabled = currentPage === totalPages || totalPages === 0;
  const startIdx = (currentPage - 1) * itemsPerPage;
  const endIdx = Math.min(startIdx + itemsPerPage, totalItems);
  rangeStart.textContent = totalItems === 0 ? "0" : (startIdx + 1).toString();
  rangeEnd.textContent = endIdx.toString();
  rows.forEach(row => {
    const idxAttr = row.getAttribute("data-index");
    if (idxAttr !== null) {
