const fs = require('fs');
let c = fs.readFileSync('src/pages/deliveries.astro', 'utf8');

// ── 1. Add drones.csv loading + reverse fuzzy match to frontmatter ──
const frontmatterEnd = c.indexOf('---', 3) + 3;
const frontmatter = c.substring(0, frontmatterEnd);

// Add drones loading after deliveries parsing
const newCode = `
// ── Load drones.csv for reverse lookup ──
const dronesCsv = fs.readFileSync(path.join(process.cwd(), 'src/data/drones.csv'), 'utf-8');
const dronesRaw = parse(dronesCsv, { columns: true, skip_empty_lines: true, cast: true });
const drones = dronesRaw.map((r) => ({
  id: String(r.id),
  location: String(r.location),
  status: String(r.status),
  attempts: Number(r.attempts),
  success: Number(r.success),
  pct: Number(r.pct),
  normalizedId: String(r.id).replace(/^DRN-/, '').toLowerCase(),
}));

// Levenshtein distance
function lev(a, b) {
  const m = a.length, n = b.length;
  const dp = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++)
    for (let j = 1; j <= n; j++)
      dp[i][j] = a[i - 1] === b[j - 1] ? dp[i - 1][j - 1] : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
  return dp[m][n];
}

// Build delivery→drone mapping (reverse lookup)
const deliveryDroneMap = {};
deliveries.forEach(d => {
  const dNorm = String(d.drone).replace(/^DR-/, '').replace(/-/g, '').toLowerCase();
  let best = null, bestScore = Infinity;
  drones.forEach(dr => {
    if (dNorm[0] === dr.normalizedId[0]) {
      const score = lev(dNorm, dr.normalizedId);
      if (score < bestScore) { bestScore = score; best = dr; }
    }
  });
  if (best && bestScore <= 3) {
    deliveryDroneMap[d.id] = { drone: best, score: bestScore };
  } else {
    deliveryDroneMap[d.id] = null;
  }
});
const deliveryDroneMapJson = JSON.stringify(deliveryDroneMap);
const dronesListJson = JSON.stringify(drones);
`;

c = c.substring(0, frontmatterEnd) + newCode + c.substring(frontmatterEnd);
console.log('1. Added drone loading + reverse mapping');

