                          delivery.type === 'transit' ? 'text-emerald-400' : 'text-slate-500'
                        }\`}>{delivery.etaDetail}</p>
                      </td>
                      <td class="py-3.5 px-5 text-center border-b border-[#131a2a]/30">
                        <div class="flex items-center justify-center gap-3 text-slate-500">
