        html += '<div class="flex items-center gap-2"><span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[9px] font-bold uppercase bg-indigo-500/10 text-indigo-400 border border-indigo-500/20">Drone</span><span class="font-mono text-xs font-bold text-slate-200">' + esc(dr.id) + '</span></div>';
        html += '<div class="text-[10px] text-slate-400">Location: <span class="text-slate-300">' + esc(dr.location) + '</span></div>';
        html += '<div class="flex items-center gap-2 text-[10px]"><span class="text-slate-500">Status:</span><span class="inline-flex items-center px-1.5 py-0.5 rounded text-[8px] font-bold uppercase border ' + drStatusColor + '">' + esc(dr.status) + '</span></div>';
        html += '<div class="flex justify-between text-[10px]"><span class="text-slate-500">Success Rate:</span><span style="color:' + pctColor + '" class="font-bold">' + dr.pct + '% (' + dr.success + '/' + dr.attempts + ')</span></div>';
        html += '<div class="w-full h-1.5 bg-[#172033] rounded-full overflow-hidden"><div class="h-full rounded-full" style="width:' + dr.pct + '%;background:' + pctColor + '"></div></div>';
        html += '</div>';
