  '<button id="mobile-menu-toggle" class="lg:hidden p-1.5 text-slate-400 hover:text-white rounded-md hover:bg-[#171f34] transition-colors shrink-0 mb-1" aria-label="Open menu"><svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 6h16M4 12h16M4 18h16"/></svg></button>\n            <button id="sidebar-collapse-btn" class="hidden lg:flex p-1.5 text-slate-400 hover:text-white rounded-md hover:bg-[#171f34] transition-colors shrink-0 mb-1" aria-label="Toggle sidebar" title="Toggle sidebar"><svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M11 19l-7-7 7-7M18 19l-7-7 7-7"/></svg></button>'
);

// ── 3. Replace Metric Grid through end of main with the two-column table ──
const metricStart = c.indexOf('<!-- Metric Grid -->');
const mainEnd = c.indexOf('</main>') + '</main>'.length;

const twoSection = `<!-- Deliveries Table + Detail Panel -->
        <div class="flex flex-col lg:flex-row border border-[#192239] rounded-xl overflow-hidden shadow-lg bg-[#0e1220]">
          <div class="flex-1 min-w-0 flex flex-col">
            <div class="overflow-x-auto overflow-y-auto max-h-[500px]">
              <table class="w-full text-left border-collapse" id="deliveries-table">
                <thead>
                  <tr class="sticky top-0 z-10 bg-[#0c0f17] shadow-[0_1px_0_0_rgba(30,41,59,0.5)]">
                    <th class="py-3.5 px-5 text-[10px] font-bold tracking-widest text-slate-400 uppercase select-none border-b-2 border-r border-[#1a233b] bg-[#0c0f17]">Delivery ID</th>
                    <th class="py-3.5 px-5 text-[10px] font-bold tracking-widest text-slate-400 uppercase select-none border-b-2 border-r border-[#1a233b] bg-[#0c0f17]">Address</th>
                    <th class="py-3.5 px-5 text-[10px] font-bold tracking-widest text-slate-400 uppercase select-none border-b-2 border-r border-[#1a233b] bg-[#0c0f17]">Drone</th>
                    <th class="py-3.5 px-5 text-[10px] font-bold tracking-widest text-slate-400 uppercase select-none border-b-2 border-r border-[#1a233b] bg-[#0c0f17]">Status</th>
                    <th class="py-3.5 px-5 text-[10px] font-bold tracking-widest text-slate-400 uppercase select-none border-b-2 border-r border-[#1a233b] bg-[#0c0f17]">ETA</th>
                    <th class="py-3.5 px-5 text-[10px] font-bold tracking-widest text-slate-400 uppercase text-center select-none border-b-2 border-[#1a233b] bg-[#0c0f17]">Action</th>
                  </tr>
                </thead>
                <tbody class="divide-y divide-[#131a2a]">
                  {deliveries.map((delivery, idx) => (
                    <tr class="even:bg-[#0b0e16]/30 hover:bg-[#131b2e] transition-colors duration-150 group delivery-row cursor-pointer" data-index={idx} data-drone={delivery.drone} data-address={delivery.address} data-id={delivery.id} data-eta={delivery.eta} data-status={delivery.status}>
                      <td class="py-3.5 px-5 font-mono text-xs font-bold text-slate-200 group-hover:text-blue-400 transition-colors border-b border-r border-[#131a2a]/30">{delivery.id}</td>
                      <td class="py-3.5 px-5 text-xs border-b border-r border-[#131a2a]/30">
                        <p class="font-bold text-slate-200">{delivery.address}</p>
                        <p class="text-[10px] text-slate-500 font-medium">{delivery.addressDetail}</p>
                      </td>
                      <td class="py-3.5 px-5 text-xs font-mono text-slate-300 border-b border-r border-[#131a2a]/30">
                        <div class="flex items-center gap-1.5">
                          <span class={\`w-1.5 h-1.5 rounded-full \${
                            delivery.type === 'transit' ? 'bg-blue-400' :
                            delivery.type === 'delayed' ? 'bg-rose-400' :
