                        )}
                        {delivery.status === "FINAL APPROACH" && (
                          <div class="inline-flex items-center gap-1.5 py-0.5 px-2 bg-emerald-500/10 border border-emerald-500/20 rounded-md text-[9px] font-bold text-emerald-400 uppercase tracking-wilder">Final Approach</div>
                        )}
                      </td>
                      <td class="py-3.5 px-5 text-xs border-b border-[#131a2a]/30">
                        <p class="font-mono font-bold text-slate-200">{delivery.eta}</p>
                        <p class={\`text-[10px] font-bold \${
                          delivery.type === 'delayed' ? 'text-rose-400' :
                          delivery.type === 'approach' ? 'text-emerald-400' :
                          delivery.type === 'transit' ? 'text-emerald-400' : 'text-slate-500'
                        }\`}>{delivery.etaDetail}</p>
                      </td>
