                        <div class="flex items-center justify-center gap-3 text-slate-500">
                          <span class="text-[9px]">View</span>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div class="p-4 bg-[#111628] border-t border-[#192239] flex justify-between items-center text-xs text-slate-400 font-semibold shrink-0">
              <span>Showing all <strong class="text-white">{deliveries.length}</strong> deliveries</span>
              <span class="text-[10px] text-slate-500">Click a row for linked drone details</span>
            </div>
          </div>
          <div class="w-full lg:w-80 xl:w-96 shrink-0 border-t lg:border-t-0 lg:border-l border-[#192239] flex flex-col bg-[#0c0f17]" id="delivery-detail-panel">
            <div class="p-5 border-b border-[#192239] shrink-0">
              <h3 class="text-sm font-extrabold text-white tracking-wide" id="panel-delivery-id">Delivery Inspector</h3>
              <p class="text-[10px] text-slate-500 mt-0.5" id="panel-subtitle">Click a delivery row to inspect</p>
            </div>
            <div class="flex-1 overflow-y-auto p-5 space-y-5" id="panel-body">
              <div class="text-center py-16">
                <Package class="w-8 h-8 text-slate-600 mx-auto mb-3" />
                <p class="text-xs text-slate-500">Select a delivery to see its full details and the linked drone.</p>
              </div>
            </div>
          </div>
        </div>
      </main>`;

c = c.substring(0, metricStart) + twoSection + '\n\n';
console.log('1. Added two-column table + panel');

// ── 4. Remove old tactical sidebar HTML ──
const tacticalStart = c.indexOf('<!-- RIGHT SIDEBAR (Tactical Airspace Map) -->');
const tacticalEnd = c.indexOf('</aside>', tacticalStart) + '</aside>'.length;
c = c.substring(0, tacticalStart) + c.substring(tacticalEnd);
console.log('2. Removed old sidebar');

// ── 5. Remove old script, add new one ──
const oldScriptStart = c.indexOf('// Interactive Sidebar logic');
const endOfFile = c.length;

// New script block
const newScript = `<!-- Detail panel + sidebar collapse + data scripts -->
<script define:vars={{ dmap: deliveryDroneMapJson }}>
  window.__DM__ = JSON.parse(dmap);
</script>
<script>
  (function () {
    var DM = window.__DM__;
    var rows = document.querySelectorAll(".delivery-row");
    var panelBody = document.getElementById("panel-body");
    var panelId = document.getElementById("panel-delivery-id");

    function esc(s) { return s ? String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;") : ""; }
    function dr(label, value, mono, color) {
      var vc = mono ? "font-mono text-slate-200" : "text-slate-200";
      var vs = color ? ' style="color:'+color+'"' : "";
      return '<div class="flex justify-between items-center py-1.5"><span class="text-[10px] font-bold text-slate-500 uppercase tracking-wider">'+label+'</span><span class="text-xs font-medium '+vc+'"'+vs+'>'+esc(String(value))+'</span></div>';
    }

    function populatePanel(row) {
      if (!panelBody) return;
      var id = row.getAttribute("data-id")||"";
      var drone = row.getAttribute("data-drone")||"";
      var addr = row.getAttribute("data-address")||"";
      var eta = row.getAttribute("data-eta")||"";
      var status = row.getAttribute("data-status")||"";
      var cells = row.querySelectorAll("td");
      var addrDet = cells[1] ? (cells[1].querySelector("p:last-child")||{}).textContent||"" : "";
      var etaDet = cells[4] ? (cells[4].querySelector("p:last-child")||{}).textContent||"" : "";

      panelId.textContent = id;
      var sc = status==="IN TRANSIT"?"border-blue-500/20 text-blue-400":
               status==="DELAYED"?"border-amber-500/20 text-amber-400":
               status==="FINAL APPROACH"?"border-emerald-500/20 text-emerald-400":
               "border-slate-500/25 text-slate-400";

      var h = '<div class="bg-[#111625] border border-[#192239] rounded-xl p-4 space-y-3 mb-4">';
      h += '<div class="flex items-center gap-2 mb-3"><span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[9px] font-bold uppercase bg-amber-500/10 text-amber-400 border border-amber-500/20">Delivery</span><span class="inline-flex items-center gap-1.5 py-0.5 px-2 rounded-md text-[10px] font-bold uppercase tracking-wider border '+sc+'">'+esc(status)+'</span></div>';
      h += dr("ID",id,true)+dr("Address",addr)+dr("Detail",addrDet)+dr("Assigned Drone",drone,true)+dr("Status",status)+dr("ETA",eta)+dr("Note",etaDet);
      h += '</div>';

      // Linked drone
      h += '<div class="pt-2"><h4 class="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-3">Linked Drone</h4>';
      var m = DM[id];
      if (m && m.drone) {
        var d = m.drone;
        var dsc = d.status==="IN-TRANSIT"?"border-blue-500/20 text-blue-400":d.status==="MAINTENANCE"?"border-rose-500/20 text-rose-400":"border-slate-500/25 text-slate-400";
        var pc = d.pct>=95?"#10b981":d.pct>=90?"#60a5fa":"#f59e0b";
        h += '<div class="bg-[#111625] border border-[#1b253b] rounded-lg p-3 space-y-2">';
        h += '<div class="flex items-center gap-2"><span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[9px] font-bold uppercase bg-indigo-500/10 text-indigo-400 border border-indigo-500/20">Drone</span><span class="font-mono text-xs font-bold text-slate-200">'+esc(d.id)+'</span></div>';
        h += '<div class="text-[10px] text-slate-400">Location: <span class="text-slate-300">'+esc(d.location)+'</span></div>';
        h += '<div class="flex items-center gap-2 text-[10px]"><span class="text-slate-500">Status:</span><span class="inline-flex items-center px-1.5 py-0.5 rounded text-[8px] font-bold uppercase border '+dsc+'">'+esc(d.status)+'</span></div>';
        h += '<div class="flex justify-between text-[10px]"><span class="text-slate-500">Success:</span><span style="color:'+pc+'" class="font-bold">'+d.pct+'% ('+d.success+'/'+d.attempts+')</span></div>';
        h += '<div class="w-full h-1.5 bg-[#172033] rounded-full overflow-hidden"><div class="h-full rounded-full" style="width:'+d.pct+'%;background:'+pc+'"></div></div></div>';
      } else {
        h += '<div class="bg-[#111625] border border-[#1b253b] rounded-lg p-3"><p class="text-xs text-slate-500">No matching drone found for <span class="font-mono text-slate-400">'+esc(drone)+'</span>.</p></div>';
      }
      h += '</div>';
      panelBody.innerHTML = h;
    }

    // Click delegation
    var tbody = document.querySelector("#deliveries-table tbody");
    if (tbody) tbody.addEventListener("click", function(e) {
      var row = e.target.closest("tr[data-id]");
      if (!row) return;
      rows.forEach(function(r) { r.classList.remove("bg-blue-950/30","border-l-2","border-blue-500"); });
      row.classList.add("bg-blue-950/30","border-l-2","border-blue-500");
      populatePanel(row);
    });

    // Sidebar collapse
    var sb = document.getElementById("left-sidebar");
    var cb = document.getElementById("sidebar-collapse-btn");
    if (sb && cb) {
      var open = true;
      cb.addEventListener("click", function() {
        open = !open;
        if (open) { sb.classList.remove("w-16"); sb.classList.add("w-64"); }
        else { sb.classList.remove("w-64"); sb.classList.add("w-16"); }
        cb.querySelector("svg").innerHTML = open
          ? '<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M11 19l-7-7 7-7M18 19l-7-7 7-7"/>'
          : '<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M13 5l7 7-7 7M6 5l7 7-7 7"/>';
      });
    }

    // Search inputs
    var si = document.getElementById("delivery-search-input");
    var hs = document.getElementById("delivery-header-search");
    function ns(el) { var q = encodeURIComponent(el.value.trim()); if (q) window.location.href = "/pluto/search?q=" + q; }
    if (si) {
      si.addEventListener("keydown", function(e) { if (e.key === "Enter") { e.preventDefault(); ns(si); } });
      si.addEventListener("input", function() {
        var q = si.value.toLowerCase().trim();
        rows.forEach(function(r) { var t = (r.textContent||"").toLowerCase(); r.classList.toggle("hidden", q && !t.includes(q)); });
      });
    }
    if (hs) hs.addEventListener("keydown", function(e) { if (e.key === "Enter") { e.preventDefault(); ns(hs); } });
  })();
</script>
</Layout>`;

c = c.substring(0, oldScriptStart) + newScript;
console.log('3. New script embedded');

fs.writeFileSync('src/pages/deliveries.astro', c, 'utf8');
console.log('Done');

