// ── 3. Replace Metric Grid → </main> with two-column table layout ──
const metricStart = c.indexOf('<!-- Metric Grid -->');
const mainClose = c.indexOf('</main>', metricStart);

const TWO_COL = `<!-- Deliveries Table + Detail Panel -->
        <div class="flex flex-col lg:flex-row border border-[#192239] rounded-xl overflow-hidden shadow-lg bg-[#0e1220]">
