                        <div class="flex items-center gap-1.5">
                          <span class={\`w-1.5 h-1.5 rounded-full \${
                            delivery.type === 'transit' ? 'bg-blue-400' :
                            delivery.type === 'delayed' ? 'bg-rose-400' :
                            delivery.type === 'approach' ? 'bg-emerald-400' : 'bg-slate-400'
                          }\`}></span>
                          {delivery.drone}
                        </div>
                      </td>
                      <td class="py-3.5 px-5 border-b border-r border-[#131a2a]/30">
                        {delivery.status === "IN TRANSIT" && (
                          <div class="inline-flex items-center gap-1.5 py-0.5 px-2 bg-blue-500/10 border border-blue-500/20 rounded-md text-[9px] font-bold text-blue-400 uppercase tracking-wider">In Transit</div>
                        )}
                        {delivery.status === "DELAYED" && (
                          <div class="inline-flex items-center gap-1.5 py-0.5 px-2 bg-rose-500/10 border border-rose-500/20 rounded-md text-[9px] font-bold text-rose-400 tracking-wider">Delayed</div>
