const frontmatter = src.substring(0, fmEnd);

// New template body
const template = `
<Layout title="PLUTO Fleet Command | Deliveries">
  <div class="flex h-screen overflow-hidden bg-[#0a0d16] relative">
    <!-- LEFT SIDEBAR -->
    <aside id="left-sidebar" class="mobile-sidebar hidden lg:flex w-64 bg-[#0e1220] border-r border-[#192239] flex-col justify-between shrink-0 fixed lg:relative inset-y-0 left-0 z-40 shadow-2xl lg:shadow-none transition-all duration-300">
      <div>
        <div class="p-6 border-b border-[#192239]">
          <div class="flex items-center gap-2.5 justify-between">
            <div class="flex items-center gap-2.5">
