              <div>
                <h1 class="text-xs uppercase font-extrabold tracking-widest text-blue-400">Pluto</h1>
                <p class="text-[10px] font-medium text-slate-500 uppercase tracking-wider">Fleet Command</p>
              </div>
            </div>
            <button id="mobile-menu-close" class="lg:hidden p-1 text-slate-400 hover:text-white -mr-1" aria-label="Close menu"><svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M6 18L18 6M6 6l12 12"/></svg></button>
          </div>
        </div>
        <nav class="p-4 space-y-1">
          <a href="/pluto/" class="flex items-center gap-3 px-4 py-3 text-sm font-medium text-slate-400 hover:text-slate-200 hover:bg-[#12192a]/50 rounded-md transition-all group"><Rocket class="w-[18px] h-[18px] text-slate-500 group-hover:text-slate-400" /> Drones</a>
          <a href="/pluto/deliveries" class="flex items-center gap-3 px-4 py-3 text-sm font-semibold text-slate-300 bg-[#171f34] border-l-2 border-blue-500 rounded-r-md transition-all"><Package class="w-[18px] h-[18px] text-blue-400" /> Deliveries</a>
          <a href="/pluto/analytics" class="flex items-center gap-3 px-4 py-3 text-sm font-medium text-slate-400 hover:text-slate-200 hover:bg-[#12192a]/50 rounded-md transition-all group"><TrendingUp class="w-[18px] h-[18px] text-slate-500 group-hover:text-slate-400" /> Analytics</a>
          <a href="/pluto/search" class="flex items-center gap-3 px-4 py-3 text-sm font-medium text-slate-400 hover:text-slate-200 hover:bg-[#12192a]/50 rounded-md transition-all group"><Search class="w-[18px] h-[18px] text-slate-500 group-hover:text-slate-400" /> Search</a>
          <a href="#" class="flex items-center gap-3 px-4 py-3 text-sm font-medium text-slate-400 hover:text-slate-200 hover:bg-[#12192a]/50 rounded-md transition-all group"><Settings class="w-[18px] h-[18px] text-slate-500 group-hover:text-slate-400" /> Settings</a>
        </nav>
      </div>
      <div class="p-4 border-t border-[#192239] bg-[#0c0f1b]">
        <div class="flex items-center gap-3">
          <div class="w-10 h-10 rounded-lg bg-[#11182c] border border-blue-500/20 text-blue-400 flex items-center justify-center font-bold shadow-inner">JB</div>
          <div class="overflow-hidden"><p class="text-xs font-semibold text-slate-200 truncate">Justin Beckenbaur</p><p class="text-[10px] text-slate-500 uppercase tracking-tight">System Admin</p></div>
        </div>
      </div>
    </aside>

    <main class="flex-1 overflow-y-auto p-4 lg:p-8 space-y-4 lg:space-y-6 bg-[#0a0d16]">
      <div class="flex items-center gap-3">
        <button id="mobile-menu-toggle" class="lg:hidden p-1.5 text-slate-400 hover:text-white rounded-md hover:bg-[#171f34] transition-colors shrink-0 mb-1" aria-label="Open menu"><svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 6h16M4 12h16M4 18h16"/></svg></button>
        <button id="sidebar-collapse-btn" class="hidden lg:flex p-1.5 text-slate-400 hover:text-white rounded-md hover:bg-[#171f34] transition-colors shrink-0 mb-1" aria-label="Toggle sidebar" title="Toggle sidebar"><svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M11 19l-7-7 7-7M18 19l-7-7 7-7"/></svg></button>
        <div>
          <h2 class="text-2xl font-extrabold tracking-tight text-white flex items-center gap-2"><Package class="w-6 h-6 text-blue-400" /> Deliveries</h2>
          <p class="text-sm font-medium text-slate-400 mt-0.5">All {deliveries.length} deliveries with linked drone inspection</p>
        </div>
      </div>

      <!-- Deliveries Table + Detail Panel -->
      <div class="flex flex-col lg:flex-row border border-[#192239] rounded-xl overflow-hidden shadow-lg bg-[#0e1220]">
        <div class="flex-1 min-w-0 flex flex-col">
          <div class="overflow-x-auto overflow-y-auto max-h-[500px]">
            <table class="w-full text-left border-collapse" id="deliveries-table">
