                  <th class="py-3.5 px-5 text-[10px] font-bold tracking-widest text-slate-400 uppercase select-none border-b-2 border-r border-[#1a233b] bg-[#0c0f17]">Address</th>
                  <th class="py-3.5 px-5 text-[10px] font-bold tracking-widest text-slate-400 uppercase select-none border-b-2 border-r border-[#1a233b] bg-[#0c0f17]">Drone</th>
                  <th class="py-3.5 px-5 text-[10px] font-bold tracking-widest text-slate-400 uppercase select-none border-b-2 border-r border-[#1a233b] bg-[#0c0f17]">Status</th>
                  <th class="py-3.5 px-5 text-[10px] font-bold tracking-widest text-slate-400 uppercase select-none border-b-2 border-r border-[#1a233b] bg-[#0c0f17]">ETA</th>
                </tr>
              </thead>
              <tbody class="divide-y divide-[#131a2a]">
                {deliveries.map((delivery, idx) => (
                  <tr class="even:bg-[#0b0e16]/30 hover:bg-[#131b2e] transition-colors duration-150 group delivery-row cursor-pointer" data-index={idx} data-drone={delivery.drone} data-address={delivery.address} data-id={delivery.id} data-eta={delivery.eta} data-status={delivery.status}>
                    <td class="py-3.5 px-5 font-mono text-xs font-bold text-slate-200 group-hover:text-blue-400 transition-colors border-b border-r border-[#131a2a]/30">{delivery.id}</td>
                    <td class="py-3.5 px-5 text-xs border-b border-r border-[#131a2a]/30"><p class="font-bold text-slate-200">{delivery.address}</p><p class="text-[10px] text-slate-500 font-medium">{delivery.addressDetail}</p></td>
                    <td class="py-3.5 px-5 text-xs font-mono text-slate-300 border-b border-r border-[#131a2a]/30">
                      <div class="flex items-center gap-1.5"><span class={\`w-1.5 h-1.5 rounded-full \${delivery.type === 'transit' ? 'bg-blue-400' : delivery.type === 'delayed' ? 'bg-rose-400' : delivery.type === 'approach' ? 'bg-emerald-400' : 'bg-slate-400'}\`}></span>{delivery.drone}</div>
                    </td>
                    <td class="py-3.5 px-5 border-b border-r border-[#131a2a]/30">
                      {delivery.status === "IN TRANSIT" && (<div class="inline-flex items-center gap-1.5 py-0.5 px-2 bg-blue-500/10 border border-blue-500/20 rounded-md text-[9px] font-bold text-blue-400 uppercase tracking-wider">In Transit</div>)}
                      {delivery.status === "DELAYED" && (<div class="inline-flex items-center gap-1.5 py-0.5 px-2 bg-rose-500/10 border border-rose-500/20 rounded-md text-[9px] font-bold text-rose-400 tracking-wider">Delayed</div>)}
                      {delivery.status === "SCHEDULED" && (<div class="inline-flex items-center gap-1.5 py-0.5 px-2 bg-slate-500/10 border border-slate-500/25 rounded-md text-[9px] font-bold text-slate-400 uppercase tracking-wider">Scheduled</div>)}
                      {delivery.status === "FINAL APPROACH" && (<div class="inline-flex items-center gap-1.5 py-0.5 px-2 bg-emerald-500/10 border border-emerald-500/20 rounded-md text-[9px] font-bold text-emerald-400 uppercase tracking-wilder">Final Approach</div>)}
                    </td>
                    <td class="py-3.5 px-5 text-xs border-b border-[#131a2a]/30">
                      <p class="font-mono font-bold text-slate-200">{delivery.eta}</p>
                      <p class={\`text-[10px] font-bold \${delivery.type === 'delayed' ? 'text-rose-400' : delivery.type === 'approach' ? 'text-emerald-400' : delivery.type === 'transit' ? 'text-emerald-400' : 'text-slate-500'}\`}>{delivery.etaDetail}</p>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div class="p-4 bg-[#111628] border-t border-[#192239] flex justify-between items-center text-xs text-slate-400 font-semibold shrink-0">
            <span>Showing all <strong class="text-white">{deliveries.length}</strong> deliveries</span>
            <span class="text-[10px] text-slate-500">Click a row for linked drone details</span>
          </div>
        </div>

        <div class="w-full lg:w-80 xl:w-96 shrink-0 border-t lg:border-t-0 lg:border-l border-[#192239] flex flex-col bg-[#0c0f17]" id="delivery-detail-panel">
          <div class="p-5 border-b border-[#192239] shrink-0">
            <h3 class="text-sm font-extrabold text-white tracking-wide" id="panel-delivery-id">Delivery Inspector</h3>
            <p class="text-[10px] text-slate-500 mt-0.5" id="panel-subtitle">Click a delivery row to inspect</p>
          </div>
          <div class="flex-1 overflow-y-auto p-5 space-y-5" id="panel-body">
            <div class="text-center py-16">
              <Package class="w-8 h-8 text-slate-600 mx-auto mb-3" />
              <p class="text-xs text-slate-500">Select a delivery to see full details and the linked drone.</p>
            </div>
          </div>
        </div>
      </div>
    </main>
  </div>
</Layout>

<script define:vars={{ dmap: JSON.stringify(deliveryDroneMap) }}>
