// ── Event: keyboard shortcuts on search input ──
searchInput.addEventListener("keydown", (e) => {
  if (e.key === "Escape") {
    searchInput.value = "";
    query = "";
    currentPage = 1;
    applyAll();
  }
  if (e.key === "Enter") {
    // Re-apply the current query so the URL updates and results refresh
    query = searchInput.value;
    currentPage = 1;
    applyAll();
  }
});

