  // Tab switching
  setTimeout(function() {
    var tabs = document.querySelectorAll(".log-tab");
    var logRows = document.querySelectorAll(".log-row");
    tabs.forEach(function(tab) {
      tab.addEventListener("click", function() {
        tabs.forEach(function(t) { t.classList.remove("border-blue-500","text-white","font-bold"); t.classList.add("border-transparent","text-slate-500","font-medium"); });
        tab.classList.add("border-blue-500","text-white","font-bold");
        tab.classList.remove("border-transparent","text-slate-500","font-medium");
        var filter = tab.getAttribute("data-tab");
        logRows.forEach(function(r) {
          if (filter === "all") r.style.display = "";
          else if (filter === "active") r.style.display = r.classList.contains("active") ? "" : "none";
          else if (filter === "delayed") r.style.display = r.classList.contains("delayed") ? "" : "none";
        });
      });
    });
  }, 50);
}

