  var linkedDrone = null;
  Object.keys(match).forEach(function(droneId) {
    var deliveries = match[droneId];
    for (var i = 0; i < deliveries.length; i++) {
      if (deliveries[i].id === deliveryId) { linkedDrone = { id: droneId, delivery: deliveries[i] }; break; }
    }
