const fs = require('fs');
let c = fs.readFileSync('src/pages/index.astro', 'utf8');

// 1. Add data-id to drone rows
c = c.replace(/data-index=\{idx\}/g, 'data-id={drone.id} data-index={idx}');
console.log('data-id added:', c.includes('data-id={drone.id}'));

// 2. Find the last </script> before </Layout> and insert handlers before it
const layoutIdx = c.lastIndexOf('</Layout>');
const scriptClose = c.lastIndexOf('</script>', layoutIdx);
const marker = c.substring(scriptClose - 40, scriptClose);

const handler = `
    // ── Drone row click → detail in drawer ──
    var droneRows = document.querySelectorAll(".drone-row");
    droneRows.forEach(function(row) {
      row.addEventListener("click", function() {
        var droneId = row.getAttribute("data-id");
        if (!droneId) return;
        droneRows.forEach(function(r) { r.classList.remove("bg-blue-950/30","border-l-2","border-blue-500"); });
        row.classList.add("bg-blue-950/30","border-l-2","border-blue-500");
        showDroneDetail(droneId);
      });
    });
    function showDroneDetail(did) {
      var cells = document.querySelector('tr[data-id="' + did + '"]').querySelectorAll("td");
      var drone = { id: did, location: cells[1]?cells[1].textContent.trim():"", status: cells[2]?cells[2].textContent.trim():"", attempts: cells[3]?parseInt(cells[3].textContent):0, pct: cells[4]?parseFloat(cells[4].textContent):0 };
      var dels = window.__DRONE_DELIVERIES__[did] || [];
      var pc = drone.pct >= 95 ? "#10b981" : drone.pct >= 90 ? "#60a5fa" : "#f59e0b";
      var drw = document.getElementById("delivery-logs-drawer");
      if (drw) { drw.classList.remove("hidden"); drw.classList.add("flex"); }
      var sc = drw ? drw.querySelector(".flex-1.overflow-y-auto") : null;
      if (!sc) return;
      var h = '<div class="p-6 space-y-4"><div class="flex items-center justify-between"><h3 class="text-md font-extrabold text-white">' + escH(drone.id) + '</h3><button onclick="document.getElementById(\\'delivery-logs-drawer\\').classList.add(\\'hidden\\')" class="p-1 bg-[#171f34] text-slate-400 hover:text-white rounded"><svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M6 18L18 6M6 6l12 12"/></svg></button></div>';
      h += '<div class="bg-[#111625] border border-[#192239] rounded-xl p-4 space-y-3"><div class="flex items-center gap-2"><span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[9px] font-bold uppercase bg-indigo-500/10 text-indigo-400 border border-indigo-500/20">Drone</span></div>';
      h += '<div class="flex justify-between items-center py-1.5"><span class="text-[10px] font-bold text-slate-500 uppercase">ID</span><span class="text-xs font-mono text-slate-200">' + escH(drone.id) + '</span></div>';
      h += '<div class="flex justify-between items-center py-1.5"><span class="text-[10px] font-bold text-slate-500 uppercase">Location</span><span class="text-xs text-slate-200">' + escH(drone.location) + '</span></div>';
      h += '<div class="flex justify-between items-center py-1.5"><span class="text-[10px] font-bold text-slate-500 uppercase">Attempts</span><span class="text-xs font-mono text-slate-200">' + drone.attempts + '</span></div>';
      h += '<div class="flex justify-between items-center py-1.5"><span class="text-[10px] font-bold text-slate-500 uppercase">Success Rate</span><span class="text-xs font-mono font-bold" style="color:' + pc + '">' + drone.pct + '%</span></div>';
      h += '<div class="w-full h-1.5 bg-[#172033] rounded-full overflow-hidden"><div class="h-full rounded-full" style="width:' + drone.pct + '%;background:' + pc + '"></div></div></div>';
      if (dels.length > 0) { h += '<h4 class="text-[10px] font-bold text-slate-400 uppercase tracking-wider pt-2">Deliveries (' + dels.length + ')</h4>'; dels.forEach(function(d) { var sc2 = d.status === "DELAYED" ? "border-rose-500/20 text-rose-400" : "border-emerald-500/20 text-emerald-400"; h += '<div class="bg-[#111625] border border-[#192239] rounded-lg p-3 mb-2"><div class="flex justify-between items-start mb-1"><span class="font-mono text-[11px] font-bold text-slate-200">' + escH(d.id) + '</span><span class="inline-flex items-center px-1.5 py-0.5 rounded text-[8px] font-bold uppercase border ' + sc2 + '">' + escH(d.status) + '</span></div><div class="text-[10px] text-slate-400">' + escH(d.address) + '</div><div class="text-[9px] text-slate-500 mt-0.5">' + escH(d.addressDetail) + '</div><div class="mt-1.5 text-[9px]"><span class="text-slate-500">ETA ' + escH(d.eta) + '</span> <span class="text-slate-600">' + escH(d.etaDetail) + '</span></div></div>'; }); }
      h += '</div>'; sc.innerHTML = h;
    }
    function escH(s) { return s ? String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;") : ""; }

    // ── Search Enter → /search ──
    var si2 = document.getElementById("drone-search-input");
    if (si2) si2.addEventListener("keydown", function(e) { if (e.key === "Enter") { e.preventDefault(); var q = encodeURIComponent(si2.value.trim()); if (q) window.location.href = "/pluto/search?q=" + q; } });
`;

c = c.substring(0, scriptClose) + handler + '\n  </script>\n\n<script define:vars={{ dmap: JSON.stringify(droneDeliveriesMap) }}>\n  window.__DRONE_DELIVERIES__ = JSON.parse(dmap);\n</script>\n' + c.substring(scriptClose + '</script>'.length);
console.log('Handler inserted:', c.includes('showDroneDetail'));

fs.writeFileSync('src/pages/index.astro', c, 'utf8');

