Assignment metadata:
- objective: Fix src/pages/index.astro in the pluto project (C:\Users\Administrator\code\pluto).

The file was restored from git (920 lines) and had frontmatter patched to add drones/deliveries imports, Navigation/Drawer imports, and fuzzy matching code. But the sidebar/drawer replacement is half-done with comment markers.

YOUR TASK: Clean up the file so it's in a working state with these changes:

1. **Sidebar**: Replace the entire old sidebar `<aside>...</aside>` block (from `<!-- LEFT SIDEBAR -->` to its `</aside>`) with simply `<Navigation activePage="drones" />`

2. **Drawer**: Replace the entire old delivery-logs-drawer `<aside>...</aside>` block (from `<!-- RIGHT SIDEBAR (Delivery Logs) -->` to its `</aside>`) with:
```html
<Drawer id="delivery-logs-drawer" title="Drone Detail">
  <p class="text-xs text-slate-500 text-center py-12">Click a drone row to see full detail and linked deliveries</p>
</Drawer>
```

3. **Add data-id to drone rows**: Change every `data-index={idx}` on `<tr>` elements to also include `data-id={drone.id}`. The pattern is: `data-index={idx}` → `data-id={drone.id} data-index={idx}`. Only in `<tr` elements with `drone-row` class.

4. **Add define:vars data script** BEFORE `</Layout>`:
```
<script define:vars={{ dmap: JSON.stringify(droneDeliveriesMap) }}>
  window.__DRONE_DELIVERIES__ = JSON.parse(dmap);
</script>
```

5. **Add drone click handler + search Enter handler** at the end of the existing `<script>` block (before the closing `</script>` tag that's BEFORE `</Layout>`). Insert this JS code right before that `</script>`:

```js
    // ── Drone row click → show detail in drawer ──
    var droneRows = document.querySelectorAll(".drone-row");
    droneRows.forEach(function(row) {
      row.addEventListener("click", function() {
        var droneId = row.getAttribute("data-id");
        if (!droneId) return;
        droneRows.forEach(function(r) { r.classList.remove("bg-blue-950/30","border-l-2","border-blue-500"); });
        row.classList.add("bg-blue-950/30","border-l-2","border-blue-500");
        showDroneDetail(droneId);
      });
    });
    function showDroneDetail(did) {
      var cells = document.querySelector('tr[data-id="' + did + '"]').querySelectorAll("td");
      var drone = { id: did, location: cells[1]?cells[1].textContent.trim():"", status: cells[2]?cells[2].textContent.trim():"", attempts: cells[3]?parseInt(cells[3].textContent):0, pct: cells[4]?parseFloat(cells[4].textContent):0 };
      var dels = window.__DRONE_DELIVERIES__[did] || [];
      var pc = drone.pct>=95?"#10b981":drone.pct>=90?"#60a5fa":"#f59e0b";
      var drw = window.__drawers && window.__drawers["delivery-logs-drawer"];
      if (drw) { drw.open(); drw.setTitle(did); }
      var h = '<div class="space-y-4">';
      h += '<div class="bg-[#111625] border border-[#192239] rounded-xl p-4 space-y-3">';
      h += '<div class="flex items-center gap-2"><span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[9px] font-bold uppercase bg-indigo-500/10 text-indigo-400 border border-indigo-500/20">Drone</span></div>';
      h += kv("ID", did, true);
      h += kv("Location", drone.location);
      h += kv("Attempts", String(drone.attempts));
      h += kv("Success Rate", drone.pct + "%", false, pc);
      h += '<div class="w-full h-1.5 bg-[#172033] rounded-full overflow-hidden"><div class="h-full rounded-full" style="width:' + drone.pct + '%;background:' + pc + '"></div></div>';
      h += '</div>';
      if (dels.length > 0) {
        h += '<h4 class="text-[10px] font-bold text-slate-400 uppercase tracking-wider pt-4">Deliveries (' + dels.length + ')</h4>';
        dels.forEach(function(d) {
          var sc = d.status==="DELAYED"?"border-rose-500/20 text-rose-400":"border-emerald-500/20 text-emerald-400";
          h += '<div class="bg-[#111625] border border-[#192239] rounded-lg p-3 mb-2"><div class="flex justify-between items-start mb-1"><span class="font-mono text-[11px] font-bold text-slate-200">' + escH(d.id) + '</span><span class="inline-flex items-center px-1.5 py-0.5 rounded text-[8px] font-bold uppercase border ' + sc + '">' + escH(d.status) + '</span></div><div class="text-[10px] text-slate-400">' + escH(d.address) + '</div><div class="text-[9px] text-slate-500 mt-0.5">' + escH(d.addressDetail) + '</div><div class="mt-1.5 text-[9px]"><span class="text-slate-500">ETA ' + escH(d.eta) + '</span> <span class="text-slate-600">' + escH(d.etaDetail) + '</span></div></div>';
        });
      }
      h += '</div>';
      if (drw) drw.setBody(h);
    }
    function kv(label, value, mono, color) {
      var vc = mono ? "font-mono text-slate-200" : "text-slate-200";
      var vs = color ? ' style="color:' + color + '"' : '';
      return '<div class="flex justify-between items-center py-1.5"><span class="text-[10px] font-bold text-slate-500 uppercase">' + label + '</span><span class="text-xs font-medium ' + vc + '"' + vs + '>' + escH(value) + '</span></div>';
    }
    function escH(s) { return s ? String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;") : ""; }

    // ── Search Enter → /search ──
