```astro
<script>
  // ─── State ──────────────────────────────────────────────────────────────
  let currentPage = 1;
  const itemsPerPage = 4;

  // ─── DOM Queries ────────────────────────────────────────────────────────
  const rows = document.querySelectorAll('.delivery-row');
  const prevBtn = document.getElementById('prev-page-btn') as HTMLButtonElement | null;
  const nextBtn = document.getElementById('next-page-btn') as HTMLButtonElement | null;
  const page1Btn = document.getElementById('page-1-btn') as HTMLButtonElement | null;
  const page2Btn = document.getElementById('page-2-btn') as HTMLButtonElement | null;
  const rangeStart = document.getElementById('range-start');
  const rangeEnd = document.getElementById('range-end');
  const searchInput = document.getElementById('delivery-search-input') as HTMLInputElement | null;

  const sidebar = document.getElementById('tactical-sidebar');
  const closeSidebarBtn = document.getElementById('close-sidebar-btn');
  const activeDroneLbl = document.getElementById('active-drone-lbl');
  const activeIdLbl = document.getElementById('active-id-lbl');
  const activeAddressLbl = document.getElementById('active-address-lbl');
  const activeEtaLbl = document.getElementById('active-eta-lbl');
  const activeStatusLbl = document.getElementById('active-status-lbl');
  const mapContainer = document.getElementById('map-iframe-container');
  const focusBtn = document.getElementById('focus-location-btn');

  const modal = document.getElementById('new-mission-modal');
  const modalContent = document.getElementById('new-mission-modal-content');
  const trigger = document.getElementById('new-mission-trigger');
  const closeModalBtn = document.getElementById('close-modal-trigger');
  const cancelModalBtn = document.getElementById('cancel-modal-trigger');
  const form = document.getElementById('new-mission-form') as HTMLFormElement | null;
  const idleZoneSelect = document.getElementById('mission-idle-zone') as HTMLSelectElement | null;
  const locationInput = document.getElementById('mission-location') as HTMLInputElement | null;
  const dueDateInput = document.getElementById('mission-due-date') as HTMLInputElement | null;
  const dueTimeSelect = document.getElementById('mission-due-time') as HTMLSelectElement | null;
  const systemTzLbl = document.getElementById('system-tz-lbl');
  const savedTrigger = document.getElementById('use-saved-address-trigger');
  const savedWrapper = document.getElementById('saved-addresses-selector');
  const hideSavedBtn = document.getElementById('hide-saved-trigger');
  const savedAddrButtons = document.querySelectorAll('.saved-addr-btn');
  const suggestionsBox = document.getElementById('autocomplete-suggestions');
  const suggestionsList = document.getElementById('suggestions-list');

  const successModal = document.getElementById('success-modal');
  const successModalContent = document.getElementById('success-modal-content');
  const dismissSuccessBtn = document.getElementById('dismiss-success-btn');
  const successId = document.getElementById('success-mission-id');
  const successDock = document.getElementById('success-mission-dock');
  const successAddress = document.getElementById('success-mission-address');

  const cancelModal = document.getElementById('cancel-mission-modal');
  const cancelCont = document.getElementById('cancel-modal-content');
  const cancelIdLbl = document.getElementById('cancel-mission-id');
  const cancelDroneLbl = document.getElementById('cancel-drone-id');
  const closeCancelBtn = document.getElementById('close-cancel-modal-btn');
  const confirmCancelBtn = document.getElementById('confirm-abort-btn');
  const cancelRowButtons = document.querySelectorAll('.cancel-mission-btn');

  let filteredRows = Array.from(rows);
  let currentSelectedAddress = '';

  // ─── Helpers ────────────────────────────────────────────────────────────
  const getGoogleMapIframeUrl = (address: string): string => {
    const query = encodeURIComponent(`${address}, Sector Airspace`);
    return `https://maps.google.com/maps?q=${query}&t=k&z=17&ie=UTF8&iwloc=&output=embed`;
  };

  const renderMap = (address: string, container: HTMLElement): void => {
    container.innerHTML = `
      <iframe
        src="${getGoogleMapIframeUrl(address)}"
        class="w-full h-full border-0 rounded-xl"
        style="filter: grayscale(0.8) contrast(1.1) invert(0.9) hue-rotate(180deg);"
        allowfullscreen=""
        loading="lazy"
        referrerpolicy="no-referrer-when-downgrade"
      ></iframe>
    `;
  };

  // ─── Pagination UI ──────────────────────────────────────────────────────
  const updateDeliveriesUI = (): void => {
    const totalItems = filteredRows.length;
    const totalPages = Math.ceil(totalItems / itemsPerPage);

    if (currentPage > totalPages) currentPage = Math.max(1, totalPages);

    // Disable/Enable states
    if (prevBtn) prevBtn.disabled = currentPage === 1;
    if (nextBtn) nextBtn.disabled = currentPage === totalPages || totalPages === 0;

    // Active / Inactive pagination values
    if (page1Btn) {
      if (currentPage === 1) {
        page1Btn.classList.add('bg-[#1d4ed8]', 'text-white');
        page1Btn.classList.remove('text-slate-500');
      } else {
        page1Btn.classList.remove('bg-[#1d4ed8]', 'text-white');
        page1Btn.classList.add('text-slate-500');
      }
    }

    if (page2Btn) {
      if (currentPage === 2) {
        page2Btn.classList.add('bg-[#1d4ed8]', 'text-white');
        page2Btn.classList.remove('text-slate-500');
      } else {
        page2Btn.classList.remove('bg-[#1d4ed8]', 'text-white');
        page2Btn.classList.add('text-slate-500');
      }
    }

    // Hide all rows initially
    rows.forEach(row => row.classList.add('hidden'));

    // Slicing Indexes
    const startIdx = (currentPage - 1) * itemsPerPage;
    const endIdx = Math.min(startIdx + itemsPerPage, totalItems);

    if (rangeStart) rangeStart.textContent = totalItems === 0 ? '0' : (startIdx + 1).toString();
    if (rangeEnd) rangeEnd.textContent = endIdx.toString();

    // Show rows matching index parameters
    filteredRows.forEach((row, i) => {
      if (i >= startIdx && i < endIdx) {
        row.classList.remove('hidden');
      }
    });
  };

  // ─── Event Wiring: Pagination Buttons ───────────────────────────────────
  if (prevBtn && nextBtn) {
    prevBtn.addEventListener('click', (e) => {
      e.preventDefault();
      if (currentPage > 1) {
        currentPage--;
        updateDeliveriesUI();
      }
    });

    nextBtn.addEventListener('click', (e) => {
      e.preventDefault();
      if (currentPage < 2) {
        currentPage++;
        updateDeliveriesUI();
      }
    });
  }

  if (page1Btn && page2Btn) {
    page1Btn.addEventListener('click', (e) => {
      e.preventDefault();
      currentPage = 1;
      updateDeliveriesUI();
    });

    page2Btn.addEventListener('click', (e) => {
      e.preventDefault();
      currentPage = 2;
      updateDeliveriesUI();
    });
  }

  // ─── Search Filter ──────────────────────────────────────────────────────
  if (searchInput) {
    searchInput.addEventListener('input', () => {
      const query = searchInput.value.toLowerCase().trim();

      filteredRows = Array.from(rows).filter(row => {
        const text = row.textContent?.toLowerCase() || '';
        return text.includes(query);
      });

      currentPage = 1;
      updateDeliveriesUI();
    });
  }

  // ─── Row Click → Sidebar + Map ──────────────────────────────────────────
  const clearRowSelection = (): void => {
    rows.forEach(r => r.classList.remove('bg-blue-950/30', 'border-l-2', 'border-blue-500'));
  };

  rows.forEach(row => {
    row.addEventListener('click', () => {
      const deliveryRow = row as HTMLElement;
      const id = deliveryRow.getAttribute('data-id') || '';
      const drone = deliveryRow.getAttribute('data-drone') || '';
      const address = deliveryRow.getAttribute('data-address') || '';
      const eta = deliveryRow.getAttribute('data-eta') || '';
      const status = deliveryRow.getAttribute('data-status') || '';

      // Highlight selected row
      clearRowSelection();
      deliveryRow.classList.add('bg-blue-950/30', 'border-l-2', 'border-blue-500');

      // Update sidebar labels — guard every possibly-null element
      if (activeDroneLbl) activeDroneLbl.textContent = `DRONE: ${drone.toUpperCase()}`;
      if (activeIdLbl) activeIdLbl.textContent = id;
      if (activeAddressLbl) activeAddressLbl.textContent = address;
      if (activeEtaLbl) activeEtaLbl.textContent = `ETA ${eta}`;

      if (activeStatusLbl) {
        activeStatusLbl.textContent = status;
        if (status === 'DELAYED') {
          activeStatusLbl.className = 'text-rose-400 text-[10px] font-bold';
        } else if (status === 'FINAL APPROACH') {
          activeStatusLbl.className = 'text-emerald-400 text-[10px] font-bold';
        } else {
          activeStatusLbl.className = 'text-blue-400 text-[10px] font-bold';
        }
      }

      currentSelectedAddress = address;

      // Render map
      if (mapContainer) {
        renderMap(address, mapContainer);
      }

      // Slide sidebar in
      if (sidebar) {
        sidebar.classList.remove('hidden');
      }
    });
  });

  if (closeSidebarBtn && sidebar) {
    closeSidebarBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      sidebar.classList.add('hidden');
      clearRowSelection();
    });
  }

  if (focusBtn) {
    focusBtn.addEventListener('click', () => {
      if (currentSelectedAddress && mapContainer) {
        renderMap(currentSelectedAddress, mapContainer);
      }
    });
  }

  // ─── Timezone Display ──────────────────────────────────────────────────
  const tzName = Intl.DateTimeFormat().resolvedOptions().timeZone;
  const tzOffsetRaw = new Date().getTimezoneOffset();
  const tzOffsetHours = Math.abs(Math.floor(tzOffsetRaw / 60));
  const tzOffsetMinutes = Math.abs(tzOffsetRaw % 60);
  const tzSign = tzOffsetRaw <= 0 ? '+' : '-';
  const tzFormatted = `UTC${tzSign}${tzOffsetHours.toString().padStart(2, '0')}:${tzOffsetMinutes.toString().padStart(2, '0')}`;

  if (systemTzLbl) {
    systemTzLbl.textContent = `${tzName} (${tzFormatted})`;
  }

  // ─── Time Dropdown ──────────────────────────────────────────────────────
  if (dueTimeSelect) {
    dueTimeSelect.innerHTML = '';
    for (let h = 0; h < 24; h++) {
