      html += `<div class="flex items-center gap-2 mb-4">
        <span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-amber-500/10 text-amber-400 border border-amber-500/20">Delivery</span>
        <span class="inline-flex items-center gap-1.5 py-0.5 px-2 rounded-md text-[11px] font-bold uppercase tracking-wider border bg-${statusColor}-500/10 border-${statusColor}-500/20 text-${statusColor}-400">${esc(record.status)}</span>
      </div>`;

      html += `<div class="space-y-3">`;
      html += detailRow("Delivery ID", record.id, true);
      html += detailRow("Address", record.address);
      html += detailRow("Detail", record.addressDetail);
      html += detailRow("Assigned Drone", record.drone, true);
      html += detailRow("Status", record.status);
      html += detailRow("ETA", record.eta);
      html += detailRow("ETA Detail", record.etaDetail);
      html += detailRow("Type", record.deliveryType);
      html += `</div>`;
    }

    drawerBody.innerHTML = html;

    if (drawerOverlay && window.innerWidth < 1024) {
      drawerOverlay.classList.remove("hidden");
      document.body.style.overflow = "hidden";
    }
  };

  const closeDrawer = () => {
    if (!drawer) return;
    drawer.style.display = "none";
    drawerOverlay?.classList.add("hidden");
    document.body.style.overflow = "";
  };

  // ── Event: search input ──
  let debounceTimer;
  searchInput.addEventListener("input", () => {
    clearTimeout(debounceTimer);
    debounceTimer = setTimeout(() => {
      query = searchInput.value;
      currentPage = 1;
      applyAll();
    }, 200);
  });

  // ── Event: keyboard shortcuts on search input ──
  searchInput.addEventListener("keydown", (e) => {
    if (e.key === "Escape") {
      searchInput.value = "";
      query = "";
      currentPage = 1;
      applyAll();
    }
    if (e.key === "Enter") {
      query = searchInput.value;
      currentPage = 1;
      applyAll();
    }
  });

  // ── Event: clear button ──
  clearBtn?.addEventListener("click", () => {
    searchInput.value = "";
    query = "";
    currentPage = 1;
    applyAll();
    searchInput.focus();
  });

  // ── Event: type filter chips ──
  qa(".type-chip").forEach((btn) => {
    btn.addEventListener("click", () => {
      qa(".type-chip").forEach((b) => toggleChip(b, false));
      toggleChip(btn, true);
      typeFilter = btn.getAttribute("data-value") || "all";
      currentPage = 1;
      applyAll();
    });
  });

  // ── Event: status filter chips ──
  qa(".status-chip").forEach((btn) => {
    btn.addEventListener("click", () => {
      qa(".status-chip").forEach((b) => toggleChip(b, false));
      toggleChip(btn, true);
      statusFilter = btn.getAttribute("data-value") || "all";
      currentPage = 1;
      applyAll();
    });
  });

  // ── Event: sort select ──
  sortSelect?.addEventListener("change", () => {
    sortMode = sortSelect.value;
    currentPage = 1;
    applyAll();
  });

  // ── Event: pagination ──
  prevPageBtn?.addEventListener("click", () => {
    if (currentPage > 1) {
      currentPage--;
      applyAll();
    }
  });
  nextPageBtn?.addEventListener("click", () => {
    const filtered = filterRecords();
    const totalPages = Math.ceil(filtered.length / ITEMS_PER_PAGE) || 1;
    if (currentPage < totalPages) {
      currentPage++;
      applyAll();
    }
  });

  // ── Keyboard shortcut: "/" focuses search ──
  document.addEventListener("keydown", (e) => {
    if (
      e.key === "/" &&
      document.activeElement !== searchInput &&
      document.activeElement?.tagName !== "INPUT" &&
      document.activeElement?.tagName !== "TEXTAREA" &&
      document.activeElement?.tagName !== "SELECT"
    ) {
      e.preventDefault();
      searchInput.focus();
      searchInput.select();
    }
  });

  // ── Click delegation on table body ──
  resultsBody.addEventListener("click", (e) => {
    const row = e.target.closest("tr[data-id][data-type]");
    if (!row) return;

    const id = row.getAttribute("data-id");
    const type = row.getAttribute("data-type");
    const record = ALL_RECORDS.find((r) => r._type === type && r.id === id);
    if (!record) return;

    // Highlight selected row
    resultsBody.querySelectorAll("tr.bg-blue-950\\/30").forEach((r) => {
      r.classList.remove("bg-blue-950/30", "border-l-2", "border-blue-500");
    });
    row.classList.add("bg-blue-950/30", "border-l-2", "border-blue-500");

    openDrawer(record);
  });

  // ── Overlay click ──
  drawerOverlay?.addEventListener("click", closeDrawer);

  // ── Escape key closes drawer ──
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape" && drawer && drawer.style.display !== "none") {
      closeDrawer();
    }
  });

  // ── Init ──
  readUrlParams();
})();
</script>
```

