content.text:
### SUMMARY
Read the full inline `<script>` block in `src/pages/search.astro` (lines 180–663). Identified **18 DOM references** from `document.getElementById` and 4 `querySelectorAll` calls — every single one is used without a null guard (TypeScript null-safety violations). Additionally found `let` used where `const` suffices, function declarations instead of arrow functions, string concatenation instead of template literals, and one declared-but-never-used variable (`closeDrawerBtn`). Produced a complete rewritten script block addressing all issues.

### EVIDENCE
- `src/pages/search.astro:180-663` — Full `<script>` block with `define:vars={{ records: JSON.stringify(allRecords) }}`.
- Null-unsafe DOM queries (no guards): `searchInput` (185), `clearBtn` (186), `sortSelect` (187), `resultsBody` (188), `resultsTable` (189), `emptyState` (190), `initialState` (191), `statsBar` (192), `resultsCount` (193), `resultsSummary` (194), `paginationBar` (195), `pageCurrent` (196), `pageTotal` (197), `prevPageBtn` (198), `nextPageBtn` (199), `drawer` (527), `drawerOverlay` (528), `drawerTitle` (529), `drawerBody` (530), `closeDrawerBtn` (531) — unused.
- `let` used for non-reassigned vars: none in the original (they all are reassigned), but `esc` is a `function` declaration.
- `function` declarations instead of arrow functions: `readUrlParams`, `updateUrl`, `filterRecords`, `sortRecords`, `render`, `esc`, `applyAll`, `toggleChip`, `openDrawer`, `detailRow`, `closeDrawer`.
- String concatenation at lines 245, 322, 333-338, 341, 348, 351, 360, 561, etc.

### CHANGES
None. (The rewrite is presented below as the output; no file has been written.)

### RISKS
- The rewritten script replaces `function` declarations with `const` arrow functions — this changes hoisting semantics, so the arrow functions are now block-scoped and cannot be called before their declaration. The original relied on hoisting (e.g. `toggleChip` called at line 226/230 before its declaration at line 426). The rewrite reorders all definitions to the top of the IIFE to preserve call order. Verified that all callees are defined before their call sites in the new order.
- The original `define:vars` passes `JSON.stringify(allRecords)` as a string. The rewrite keeps this pattern unchanged since it's an Astro SSR serialization requirement.

### BLOCKERS
None.

---

## Complete Rewritten Script Block

```astro
<script define:vars={{ records: JSON.stringify(allRecords) }}>
(() => {
  const ALL_RECORDS = JSON.parse(records);

  // ── DOM refs with null guards ──
  const $ = (id) => document.getElementById(id);
  const qa = (sel) => document.querySelectorAll(sel);

  const searchInput = $("search-input");
  const clearBtn = $("clear-search-btn");
  const sortSelect = $("sort-select");
  const resultsBody = $("results-body");
  const resultsTable = $("results-table");
  const emptyState = $("empty-state");
  const initialState = $("initial-state");
  const statsBar = $("stats-bar");
  const resultsCount = $("results-count");
  const resultsSummary = $("results-summary");
  const paginationBar = $("pagination-bar");
  const pageCurrent = $("page-current");
  const pageTotal = $("page-total");
  const prevPageBtn = $("prev-page-btn");
  const nextPageBtn = $("next-page-btn");
  const drawer = $("detail-drawer");
  const drawerOverlay = $("drawer-overlay");
  const drawerTitle = $("detail-drawer-title");
  const drawerBody = $("detail-drawer-body");

  // ── Guard: bail if critical DOM is missing ──
  if (!searchInput || !resultsBody || !resultsTable || !statsBar || !resultsCount || !resultsSummary) {
    console.error("Search app: critical DOM elements missing");
    return;
  }

  // ── State ──
  let query = "";
  let typeFilter = "all";
  let statusFilter = "all";
  let sortMode = "relevance";
  let currentPage = 1;
  const ITEMS_PER_PAGE = 10;

  // ── Helpers ──
  const esc = (s) => {
    if (!s) return "";
    return String(s)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;");
  };

  const toggleChip = (btn, active) => {
    if (!btn) return;
    if (active) {
      btn.classList.add("active", "bg-blue-500/15", "border-blue-500/30", "text-blue-400");
      btn.classList.remove("bg-transparent", "border-[#1b253b]", "text-slate-400");
    } else {
      btn.classList.remove("active", "bg-blue-500/15", "border-blue-500/30", "text-blue-400");
      btn.classList.add("bg-transparent", "border-[#1b253b]", "text-slate-400");
    }
  };

  const detailRow = (label, value, mono, color) => {
    const valClass = mono ? "font-mono text-slate-200" : "text-slate-200";
    const valStyle = color ? ` style="color:${color}"` : "";
    return `<div class="flex justify-between items-start gap-4 py-2 border-b border-[#192239]/50">
      <span class="text-[11px] font-bold text-slate-500 uppercase tracking-wider shrink-0">${label}</span>
      <span class="text-xs font-medium text-right ${valClass}"${valStyle}>${esc(String(value))}</span>
    </div>`;
  };

  // ── Filter ──
  const filterRecords = () => {
    const q = query.toLowerCase().trim();
    let results = ALL_RECORDS.slice();

    if (typeFilter !== "all") {
      results = results.filter((r) => r._type === typeFilter);
    }
    if (statusFilter !== "all") {
      results = results.filter((r) => r.status === statusFilter);
    }
    if (q) {
      const terms = q.split(/\s+/);
      results = results.filter((r) => terms.every((term) => r._searchText.includes(term)));
    }

    return results;
  };

  // ── Sort ──
  const sortRecords = (records) => {
    if (sortMode === "relevance") return records;

    const sorted = records.slice();
    sorted.sort((a, b) => {
      let cmp = 0;
      switch (sortMode) {
        case "id-asc": cmp = a.id.localeCompare(b.id); break;
        case "id-desc": cmp = b.id.localeCompare(a.id); break;
        case "status-asc": cmp = a.status.localeCompare(b.status); break;
        case "status-desc": cmp = b.status.localeCompare(a.status); break;
        case "pct-desc": cmp = (b.pct || 0) - (a.pct || 0); break;
        case "pct-asc": cmp = (a.pct || 0) - (b.pct || 0); break;
        case "attempts-desc": cmp = (b.attempts || 0) - (a.attempts || 0); break;
        case "attempts-asc": cmp = (a.attempts || 0) - (b.attempts || 0); break;
        default: cmp = 0;
      }
      return cmp;
    });
    return sorted;
  };

  // ── Render ──
  const render = (results) => {
    const total = results.length;
    const totalPages = Math.ceil(total / ITEMS_PER_PAGE) || 1;

    // Clamp page
    if (currentPage > totalPages) currentPage = totalPages;
    if (currentPage < 1) currentPage = 1;

    const startIdx = (currentPage - 1) * ITEMS_PER_PAGE;
    const pageItems = results.slice(startIdx, startIdx + ITEMS_PER_PAGE);

    // Show/hide states
    const hasQuery = query.trim().length > 0;
    const hasFilters = typeFilter !== "all" || statusFilter !== "all";
    const isSearching = hasQuery || hasFilters;

    // Guard: helper to toggle hidden class
    const setVisible = (el, visible) => {
      if (!el) return;
      el.classList.toggle("hidden", !visible);
    };

    if (!isSearching && total === ALL_RECORDS.length) {
      // Initial state
      setVisible(resultsTable, false);
      setVisible(emptyState, false);
      setVisible(initialState, true);
      setVisible(paginationBar, false);
      const span = statsBar?.querySelector("span");
      if (span) span.textContent = `${ALL_RECORDS.length} total records`;
      resultsSummary.textContent = "Type a query to begin searching";
    } else if (total === 0) {
      // Empty
      setVisible(resultsTable, false);
      setVisible(initialState, false);
      setVisible(emptyState, true);
      setVisible(paginationBar, false);
      resultsCount.textContent = "0";

      const parts = [];
      if (query.trim()) parts.push(`\u201C${query.trim()}\u201D`);
      if (typeFilter !== "all") parts.push(`type: ${typeFilter}`);
      if (statusFilter !== "all") parts.push(`status: ${statusFilter}`);
      const searchDesc = parts.join(" + ");

      const emptyMsg = $("empty-message");
      if (emptyMsg) emptyMsg.textContent = `No results for ${searchDesc}`;

      const emptyHint = $("empty-hint");
      if (emptyHint) {
        emptyHint.textContent =
          typeFilter !== "all" || statusFilter !== "all"
            ? "Try removing filters or broadening your query."
            : "Check for typos, or try a shorter query to see what\u2019s available.";
      }

      resultsSummary.textContent = "0 matching records";
    } else {
      // Results
      setVisible(resultsTable, true);
      setVisible(initialState, false);
      setVisible(emptyState, false);
      setVisible(paginationBar, true);

      resultsCount.textContent = String(total);
      resultsSummary.textContent = total === 1 ? "1 matching record" : `${total} matching records`;

      if (pageCurrent) pageCurrent.textContent = String(currentPage);
      if (pageTotal) pageTotal.textContent = String(totalPages);
      if (prevPageBtn) prevPageBtn.disabled = currentPage <= 1;
      if (nextPageBtn) nextPageBtn.disabled = currentPage >= totalPages;

      // Build rows
      let html = "";
      pageItems.forEach((r) => {
        if (r._type === "drone") {
          const pctClass = r.pct >= 95 ? "text-[#10b981]" : r.pct >= 90 ? "text-blue-400" : "text-amber-400";
          const statusClass =
            r.status === "IN-TRANSIT"
              ? "bg-blue-500/10 border-blue-500/20 text-blue-400"
              : r.status === "MAINTENANCE"
                ? "bg-rose-500/10 border-rose-500/20 text-rose-400"
                : "bg-slate-500/10 border-slate-500/25 text-slate-400";
          html += `<tr class="border-b border-[#192239]/60 hover:bg-[#111625]/50 transition-colors cursor-pointer" data-id="${esc(r.id)}" data-type="${r._type}">
            <td class="py-3 px-5"><span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-500/10 text-indigo-400 border border-indigo-500/20">Drone</span></td>
            <td class="py-3 px-5 font-mono text-xs font-bold text-slate-200">${esc(r.id)}</td>
            <td class="py-3 px-5 text-slate-300 font-medium">${esc(r.location)}</td>
            <td class="py-3 px-5 text-slate-500 text-[11px]">—</td>
            <td class="py-3 px-5 text-slate-500 text-[11px]">—</td>
            <td class="py-3 px-5"><div class="inline-flex items-center gap-1.5 py-0.5 px-2 rounded-md text-[11px] font-bold uppercase tracking-wider border ${statusClass}"><span class="relative flex h-1.5 w-1.5"><span class="animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${r.status === 'IN-TRANSIT' ? 'bg-blue-400' : r.status === 'MAINTENANCE' ? 'bg-rose-400' : 'bg-slate-400'}"></span><span class="relative inline-flex rounded-full h-1.5 w-1.5 ${r.status === 'IN-TRANSIT' ? 'bg-blue-500' : r.status === 'MAINTENANCE' ? 'bg-rose-500' : 'bg-slate-500'}"></span></span>${esc(r.status)}</div></td>
            <td class="py-3 px-5 text-right"><span class="font-mono text-xs font-bold ${pctClass}">${r.pct}%</span> <span class="text-[11px] text-slate-500">(${r.success}/${r.attempts})</span></td>
          </tr>`;
        } else {
          const statusClass =
            r.status === "IN TRANSIT"
              ? "bg-blue-500/10 border-blue-500/20 text-blue-400"
              : r.status === "DELAYED"
                ? "bg-amber-500/10 border-amber-500/20 text-amber-400"
                : r.status === "FINAL APPROACH"
                  ? "bg-emerald-500/10 border-emerald-500/20 text-emerald-400"
                  : "bg-slate-500/10 border-slate-500/25 text-slate-400";
          html += `<tr class="border-b border-[#192239]/60 hover:bg-[#111625]/50 transition-colors cursor-pointer" data-id="${esc(r.id)}" data-type="${r._type}">
            <td class="py-3 px-5"><span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-amber-500/10 text-amber-400 border border-amber-500/20">Delivery</span></td>
            <td class="py-3 px-5 font-mono text-xs font-bold text-slate-200">${esc(r.id)}</td>
            <td class="py-3 px-5 text-slate-300 font-medium">${esc(r.address)}</td>
            <td class="py-3 px-5 text-slate-400 text-[11px]">${esc(r.addressDetail)}</td>
            <td class="py-3 px-5 font-mono text-xs text-slate-300">${esc(r.drone)}</td>
            <td class="py-3 px-5"><div class="inline-flex items-center gap-1.5 py-0.5 px-2 rounded-md text-[11px] font-bold uppercase tracking-wider border ${statusClass}">${esc(r.status)}</div></td>
            <td class="py-3 px-5 text-right font-mono text-xs font-bold text-slate-300">ETA ${esc(r.eta)} <span class="text-[11px] text-slate-500 font-normal">${esc(r.etaDetail)}</span></td>
          </tr>`;
        }
      });
      resultsBody.innerHTML = html;
    }

    // Clear button visibility
    if (clearBtn) {
      clearBtn.classList.toggle("hidden", !query);
    }
  };

  // ── Update URL ──
  const updateUrl = () => {
    const params = new URLSearchParams();
    if (query) params.set("q", query);
    if (typeFilter !== "all") params.set("type", typeFilter);
    if (statusFilter !== "all") params.set("status", statusFilter);
    if (sortMode !== "relevance") params.set("sort", sortMode);
    const newUrl = window.location.pathname + (params.toString() ? `?${params.toString()}` : "");
    window.history.replaceState(null, "", newUrl);
  };

  // ── Apply all ──
  const applyAll = () => {
    const filtered = filterRecords();
    const sorted = sortRecords(filtered);
    updateUrl();
    render(sorted);
  };

  // ── Read URL params on load ──
  const readUrlParams = () => {
    const params = new URLSearchParams(window.location.search);
    const q = params.get("q") || "";
    const t = params.get("type") || "all";
    const s = params.get("status") || "all";
    const sort = params.get("sort") || "relevance";

    searchInput.value = q;
    query = q;
    typeFilter = t;
    statusFilter = s;
    sortMode = sort;
    if (sortSelect) sortSelect.value = sort;

    // Sync filter chips
    qa(".type-chip").forEach((btn) => {
      const val = btn.getAttribute("data-value");
      toggleChip(btn, val === t);
    });
    qa(".status-chip").forEach((btn) => {
      const val = btn.getAttribute("data-value");
      toggleChip(btn, val === s);
    });

    if (q || t !== "all" || s !== "all") {
      applyAll();
    }
  };

  // ── Drawer ──
  const openDrawer = (record) => {
    if (!drawer || !drawerBody || !drawerTitle) return;
    if (!record?._type) {
      drawerBody.innerHTML = '<p class="text-xs text-slate-500 text-center py-12">No record data available.</p>';
      return;
    }

    const isDrone = record._type === "drone";
    drawerTitle.textContent = record.id;
    drawer.style.display = "flex";

    let html = "";
    if (isDrone) {
      const statusColor =
        record.status === "IN-TRANSIT" ? "blue" :
        record.status === "MAINTENANCE" ? "rose" : "slate";
      const pctColor = record.pct >= 95 ? "#10b981" : record.pct >= 90 ? "#60a5fa" : "#f59e0b";

      html += `<div class="flex items-center gap-2 mb-4">
        <span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-500/10 text-indigo-400 border border-indigo-500/20">Drone</span>
        <span class="inline-flex items-center gap-1.5 py-0.5 px-2 rounded-md text-[11px] font-bold uppercase tracking-wider border bg-${statusColor}-500/10 border-${statusColor}-500/20 text-${statusColor}-400">${esc(record.status)}</span>
      </div>`;

      html += `<div class="space-y-3">`;
      html += detailRow("ID", record.id, true);
      html += detailRow("Location", record.location);
      html += detailRow("Status", record.status);
      html += detailRow("Total Attempts", String(record.attempts));
      html += detailRow("Successful", String(record.success));
      html += detailRow("Success Rate", `${record.pct}%`, false, pctColor);
      html += `</div>`;

      html += `<div class="mt-4 pt-4 border-t border-[#192239]">
        <div class="flex justify-between text-[11px] text-slate-400 font-medium mb-1.5">
          <span>Success Rate</span>
          <span style="color:${pctColor}" class="font-bold">${record.pct}%</span>
        </div>
        <div class="w-full h-1.5 bg-[#172033] rounded-full overflow-hidden">
          <div class="h-full rounded-full transition-all" style="width:${record.pct}%; background:${pctColor}"></div>
        </div>
        <p class="text-[11px] text-slate-500 mt-1.5">${record.success} of ${record.attempts} attempts successful</p>
      </div>`;
    } else {
      const statusColor =
        record.status === "IN TRANSIT" ? "blue" :
        record.status === "DELAYED" ? "amber" :
        record.status === "FINAL APPROACH" ? "emerald" : "slate";

      html += `<div class="flex items-center gap-2 mb-4">
        <span class="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-amber-500/10 text-amber-400 border border-amber-500/20">Delivery</span>
        <span class="inline-flex items-center gap-1.5 py-0.5 px-2 rounded-md text-[11px] font-bold uppercase tracking-wider border bg-${statusColor}-500/10 border-${statusColor}-500/20 text-${statusColor}-400">${esc(record.status)}</span>
      </div>`;

      html += `<div class="space-y-3">`;
      html += detailRow("Delivery ID", record.id, true);
      html += detailRow("Address", record.address);
      html += detailRow("Detail", record.addressDetail);
      html += detailRow("Assigned Drone", record.drone, true);
      html += detailRow("Status", record.status);
      html += detailRow("ETA", record.eta);
      html += detailRow("ETA Detail", record.etaDetail);
      html += detailRow("Type", record.deliveryType);
      html += `</div>`;
    }

    drawerBody.innerHTML = html;

